  ) VALUES (
    'mediterranean', 'Mediterranean', 'balanced', '🫒', 'Olive oil, fish, whole grains — the gold-standard for longevity',
    'A', 2, 0, 0,
    'MEDITERRANEAN DIET RULES — Follow strictly:

1. PRIMARY FAT: Use extra virgin olive oil as the main cooking and finishing fat. Do NOT use butter, margarine, or vegetable oils.

2. VEGETABLES: Every meal should be vegetable-forward. Aim for 4+ servings of vegetables per day across meals. Use a colorful variety (leafy greens, tomatoes, peppers, eggplant, zucchini).

3. FISH: Include fish or seafood at least 2-3 times per week. Prioritize fatty fish (salmon, sardines, mackerel) for omega-3 content.

4. WHOLE GRAINS: Use only whole grains (whole wheat, brown rice, quinoa, farro, bulgur, oats). Avoid white/refined grains.

5. LEGUMES: Include legumes (lentils, chickpeas, beans) at least 3 times per week as a protein source.

6. RED MEAT: Limit red meat to a few times per MONTH. Small portions only (85-120g). Never feature red meat as the main protein in consecutive meals.

7. PROCESSED MEAT: Do NOT include processed meats (sausage, bacon, deli meat, hot dogs).

8. DAIRY: Moderate amounts — Greek yogurt, feta/goat/parmesan cheese. Keep cheese portions to 30-40g per meal.

9. FLAVOR: Season with herbs, spices, garlic, lemon juice, and olive oil instead of salt.

10. NUTS: Include a handful of nuts (almonds, walnuts) daily.

11. DESSERT: Default dessert is fresh fruit. Sweets should be occasional and small.

12. WINE: May include 1 glass of red wine with dinner (optional — do not add to breakfast or lunch).', '["leafy-greens","tomatoes","alliums","cruciferous","peppers","root-vegetables","nightshades","cucurbit-vegetables","artichokes","berries","citrus","stone-fruit","grapes","pome-fruit","melons","whole-grains","pasta-whole-grain","olive-oil","olives","fish-fatty","fish-lean","seafood","poultry","eggs","legumes","nuts","seeds","yogurt","cheese","ricotta-mozzarella","herbs","spices","lemon-lime","garlic","water","coffee","tea","red-wine"]', '["red-meat","processed-meat","refined-grains","refined-sugar","sugary-drinks","fast-food","ultra-processed-food","butter","margarine","industrial-sauces"]', '{"salmon":"fish-fatty","sardines":"fish-fatty","mackerel":"fish-fatty","tuna":"fish-fatty","cod":"fish-lean","sea bass":"fish-lean","shrimp":"seafood","mussels":"seafood","chicken":"poultry","turkey":"poultry","beef":"red-meat","pork":"red-meat","lamb":"red-meat","bacon":"processed-meat","sausage":"processed-meat","lentils":"legumes","chickpeas":"legumes","black beans":"legumes","brown rice":"whole-grains","quinoa":"whole-grains","farro":"whole-grains","whole wheat pasta":"pasta-whole-grain","white rice":"refined-grains","white bread":"refined-grains","extra virgin olive oil":"olive-oil","olive oil":"olive-oil","butter":"butter","margarine":"margarine","almonds":"nuts","walnuts":"nuts","greek yogurt":"yogurt","feta":"cheese","parmesan":"cheese"}',
    '["dash","mind","flexitarian","volumetrics","high-protein"]', '{"vegan":"Make the meal plant-based (Mediterranean is already plant-forward); add fish/poultry only for the non-vegan partners plate","vegetarian":"Same base meal; fish/poultry as a side option","pescatarian":"Nearly identical — Mediterranean already emphasizes fish","keto":"Focus on the fish + vegetables + olive oil components; skip grains/legumes for keto partner","paleo":"Focus on fish + vegetables + nuts + olive oil; skip grains/dairy/legumes for paleo partner","low-fodmap":"Adapt the recipe — reduce garlic/onion (use garlic-infused oil), choose low-FODMAP vegetables, moderate legumes"}', '{"carnivore":"Very difficult — Mediterranean is plant-forward; suggest separate meals with a shared protein (e.g., grilled fish/steak) and the carnivore partner skips the plant components","mcdougall":"Opposite fat philosophy (McDougall is very low fat); suggest separate meals","pritikin":"Opposite fat philosophy (Pritikin is <10% fat); suggest separate meals","hclf-811":"Opposite philosophy (raw, high-carb, low-fat); suggest separate meals"}'
