INSERT INTO diet_catalog (
    diet_key, display_label, category, emoji, short_desc,
    evidence_grade, restrictiveness, is_timing_pattern, is_default,
    ai_rules, allowed_groups, restricted_groups, classifier_terms,
    easy_matches, adaptable_matches, hard_conflicts
  ) VALUES (
    'dash', 'DASH', 'therapeutic', '❤️', 'NIH-designed diet to lower blood pressure — high potassium, low sodium',
    'A', 2, 0, 0,
    'DASH DIET RULES — Follow strictly:

1. SODIUM: All meals must be designed to keep total daily sodium ≤2,300mg (target: ≤1,500mg). Do NOT add salt in cooking or at the table. Use herbs, spices, citrus juice, vinegar, and no-salt seasoning blends instead.

2. VEGETABLES: Aim for 4–5 servings of vegetables per day across meals. Use a colorful variety (leafy greens, tomatoes, broccoli, carrots, peppers, sweet potatoes).

3. FRUITS: Aim for 4–5 servings of fruit per day. Include potassium-rich fruits (bananas, oranges, cantaloupe) prominently.

4. DAIRY: Include 2–3 servings of fat-free or low-fat dairy per day (milk, plain yogurt, low-fat cheese). This is essential for calcium and BP-lowering.

5. WHOLE GRAINS: Use only whole grains (100% whole wheat bread, brown rice, oats, quinoa, barley). Avoid white/refined grains. Aim for 6–8 servings/day.

6. SODIUM IN PROCESSED FOODS: Do NOT use processed meats (deli meat, sausage, bacon, hot dogs). Avoid restaurant/ultra-processed foods. Use only "no salt added" or "low sodium" canned goods.

7. LEAN PROTEINS: Use skinless poultry, fish, eggs (whites preferred), legumes, and tofu. Fish 2–3 times per week.

8. NUTS AND SEEDS: Include unsalted nuts, seeds, or legumes 4–5 times per week. Always UNSALTED.

9. RED MEAT: Limit red meat to small portions (3 oz) occasionally — not daily.

10. FATS: Use small amounts of olive oil, canola oil, or soft tub margarine (trans-fat-free). Avoid butter and solid fats.

11. SWEETS: Limit to ≤5 small servings per week. Default dessert is fresh fruit.

12. FLAVOR: Season with herbs, spices, garlic, lemon/lime juice, vinegar, and no-salt blends — never with salt or high-sodium condiments.

13. SODIUM-SPECIFIC RULES:
    - Do NOT use soy sauce (use coconut aminos or low-sodium soy sparingly)
    - Do NOT use bouillon cubes or regular broth (use low-sodium broth)
    - Do NOT use pickles or pickled vegetables
    - Rinse any canned beans or vegetables before using
    - Check bread sodium — choose varieties with ≤150mg per slice', '["leafy-greens","tomatoes","alliums","cruciferous","peppers","root-vegetables","squash-eggplant","green-beans-peas","cucumbers","citrus","berries","bananas","pome-fruit","stone-fruit","melons","grapes-cherries","dried-fruit","low-fat-milk","low-fat-yogurt","low-fat-cheese","low-fat-cottage-cheese","whole-grains","whole-grain-pasta","whole-grain-cereal","whole-grain-crackers","poultry-skinless","fish-fatty","fish-lean","eggs","legumes","tofu","nuts-unsalted","seeds-unsalted","nut-butters","olive-oil","canola-oil","soft-margarine","avocado","light-mayonnaise","herbs","spices","lemon-lime","vinegar","garlic","no-salt-blends","water","sparkling-water","coffee","tea"]', '["high-sodium-foods","processed-meat","salt","soy-sauce","red-meat","full-fat-dairy","fried-food","salty-snacks","refined-grains","sugary-drinks","refined-sugar","fast-food","ultra-processed-food","pickled-foods","bouillon-broth"]', '{"salmon":"fish-fatty","sardines":"fish-fatty","mackerel":"fish-fatty","tuna":"fish-fatty","cod":"fish-lean","halibut":"fish-lean","tilapia":"fish-lean","chicken breast":"poultry-skinless","turkey breast":"poultry-skinless","turkey":"poultry-skinless","beef":"red-meat","pork":"red-meat","lamb":"red-meat","bacon":"processed-meat","sausage":"processed-meat","ham":"processed-meat","deli meat":"processed-meat","hot dog":"processed-meat","lentils":"legumes","chickpeas":"legumes","black beans":"legumes","tofu":"tofu","egg whites":"eggs","egg":"eggs","brown rice":"whole-grains","quinoa":"whole-grains","oats":"whole-grains","steel-cut oats":"whole-grains","barley":"whole-grains","farro":"whole-grains","100% whole wheat bread":"whole-grains","whole wheat pasta":"whole-grain-pasta","white rice":"refined-grains","white bread":"refined-grains","fat-free milk":"low-fat-milk","1% milk":"low-fat-milk","skim milk":"low-fat-milk","plain greek yogurt":"low-fat-yogurt","low-fat yogurt":"low-fat-yogurt","part-skim mozzarella":"low-fat-cheese","cottage cheese":"low-fat-cottage-cheese","whole milk":"full-fat-dairy","cream":"full-fat-dairy","butter":"full-fat-dairy","olive oil":"olive-oil","canola oil":"canola-oil","avocado":"avocado","almonds":"nuts-unsalted","walnuts":"nuts-unsalted","pistachios":"nuts-unsalted","sunflower seeds":"seeds-unsalted","peanut butter":"nut-butters","table salt":"salt","sea salt":"salt","kosher salt":"salt","soy sauce":"soy-sauce","pickles":"pickled-foods","bouillon":"bouillon-broth","lemon juice":"lemon-lime","lime juice":"lemon-lime","balsamic vinegar":"vinegar","apple cider vinegar":"vinegar","garlic":"garlic"}',
    '["mediterranean","mind","flexitarian","volumetrics","high-protein","plant-based"]', '{"vegan":"Make meals plant-based; use fortified plant milk for dairy component; ensure adequate calcium/potassium from vegetables","vegetarian":"Same base meal; add lean poultry/fish only for non-vegetarian partner","pescatarian":"Nearly identical — DASH already emphasizes fish","keto":"Focus on the fish + vegetables + olive oil components; replace grains with extra non-starchy vegetables for keto partner; may conflict with DASHs high-carb whole grains","paleo":"Focus on lean meat/poultry/fish + vegetables + nuts; skip grains and dairy for paleo partner","low-fodmap":"Adapt — reduce garlic/onion (use garlic-infused oil), choose low-FODMAP vegetables, moderate legumes"}', '{"carnivore":"Very difficult — DASH is plant-forward with specific produce/dairy targets; suggest separate meals with shared lean protein","mcdougall":"Partial overlap (both high-carb, plant-forward) but DASH includes dairy and lean meat which McDougall restricts","pritikin":"Broadly compatible (both low-fat, low-sodium) — Pritikin is even more restrictive; easy adaptation"}'
  );
INSERT INTO diet_catalog (
    diet_key, display_label, category, emoji, short_desc,
    evidence_grade, restrictiveness, is_timing_pattern, is_default,
    ai_rules, allowed_groups, restricted_groups, classifier_terms,
    easy_matches, adaptable_matches, hard_conflicts
  ) VALUES (
    'intermittent-fasting', 'Intermittent Fasting', 'timing', '⏰', 'Eat within a timed window — 16:8, 5:2, OMAD and more',
    'B', 3, 1, 0,
    'INTERMITTENT FASTING RULES — Follow strictly:

TIMING IS THE PRIMARY RULE:
1. EATING WINDOW: All meals and snacks must fall within the user''s designated eating window. Do NOT generate any food items outside this window.

2. FASTING WINDOW: During the fasting period, only the following are allowed: water (still or sparkling), black coffee, unsweetened plain tea (black, green, or herbal), and zero-calorie electrolyte water. Do NOT generate meals, snacks, smoothies, or any caloric food during the fast.

3. MEAL COUNT: Generate the appropriate number of meals for the protocol:
   - 16:8 → 2-3 meals within 8 hours
   - 18:6 → 2 meals + optional snack within 6 hours
   - 20:4 → 1-2 meals within 4 hours
   - 5:2 normal day → 3 normal meals
   - 5:2 fasting day → 1-2 very small meals totaling 500-600 calories
   - ADF feast day → 3-4 meals at maintenance or above
   - ADF fast day → 1-2 very small meals totaling 500-600 calories (modified) or 0 (strict)
   - OMAD → 1 single meal

4. PROTEIN PRIORITY: Each meal in the eating window must contain a substantial protein portion (20-40g per meal). This is CRITICAL for preserving lean muscle mass during fasting periods. If the eating window allows only 1-2 meals, protein per meal must be higher (30-50g).

5. BREAK THE FAST GENTLY: The first meal after fasting should NOT be extremely large or heavy. Start with protein and fiber. Avoid massive sugar/carbohydrate loads that could cause reactive hypoglycemia.

6. LAST MEAL SATIETY: The final meal before the fasting window should be filling and satisfying to make the fast easier. Include protein, fiber, and healthy fats for sustained satiety.

7. NUTRIENT DENSITY: Because fewer meals are consumed, each meal must be nutrient-dense. Prioritize vegetables, high-quality protein, and healthy fats. Do NOT waste the limited eating window on empty calories.

8. FOOD DIET STACKING: Apply the user''s food_diet rules IN ADDITION to these timing rules. For example:
   - If food_diet is "mediterranean" + fasting_mode is "16-8": Generate Mediterranean-compliant meals within a 12:00-20:00 window
   - If food_diet is "keto" + fasting_mode is "18-6": Generate keto-compliant meals within a 13:00-19:00 window
   - If food_diet is null + fasting_mode is "16-8": Generate healthy balanced meals within the window (no specific food restrictions)

9. FASTING DAY (5:2 and ADF): On designated fasting days, generate only 500-600 calories total. Prioritize protein and vegetables to maximize satiety per calorie. Example: 2 boiled eggs + vegetables (200 cal), grilled chicken breast + salad (300 cal).

10. HYDRATION: Include a note about hydration. Suggest water, black coffee, or herbal tea during the fasting window.

11. ELECTROLYTES: For fasting windows >16 hours, suggest a pinch of salt in water or an electrolyte supplement to prevent headaches and fatigue.', '[]', '[]', '{"water":"fasting-safe","sparkling water":"fasting-safe","mineral water":"fasting-safe","black coffee":"fasting-safe","espresso":"fasting-safe","americano":"fasting-safe","green tea":"fasting-safe","black tea":"fasting-safe","herbal tea":"fasting-safe","peppermint tea":"fasting-safe","chamomile tea":"fasting-safe","rooibos tea":"fasting-safe","latte":"fasting-breaking","cappuccino":"fasting-breaking","flat white":"fasting-breaking","milk":"fasting-breaking","cream":"fasting-breaking","sugar":"fasting-breaking","honey":"fasting-breaking","juice":"fasting-breaking","smoothie":"fasting-breaking","protein shake":"fasting-breaking","bone broth":"fasting-breaking","diet soda":"fasting-breaking","coconut water":"fasting-breaking","almond milk (unsweetened)":"fasting-safe","apple cider vinegar":"fasting-safe"}',
    '[]', '{}', '{}'
  );
INSERT INTO diet_catalog (
    diet_key, display_label, category, emoji, short_desc,
    evidence_grade, restrictiveness, is_timing_pattern, is_default,
    ai_rules, allowed_groups, restricted_groups, classifier_terms,
    easy_matches, adaptable_matches, hard_conflicts
  ) VALUES (
    'keto', 'Keto / Low-Carb', 'lowCarb', '🥩', 'Very low carb, high fat — metabolic ketosis for fat-burning and blood sugar control',
    'B', 4, 0, 0,
    'KETOGENIC DIET RULES — Follow strictly:

1. CARBOHYDRATE LIMIT: Every generated day must total UNDER 50g NET CARBS (total carbs minus fiber). Aim for 20-35g net carbs for a standard day. This is the single most important constraint.

2. FAT AS PRIMARY ENERGY: Every meal must be fat-forward. Use generous amounts of olive oil, butter, avocado oil, coconut oil, or animal fats for cooking and dressing. Do NOT use low-fat ingredients.

3. PROTEIN: Include a quality protein source at every meal (meat, fish, eggs, poultry). Portions of 150-225g (5-8oz) per main meal are appropriate.

4. VEGETABLES: Include non-starchy vegetables at most meals (spinach, kale, zucchini, cauliflower, broccoli, asparagus, Brussels sprouts, avocado). These are the primary fiber and micronutrient source. NEVER include starchy vegetables (potatoes, sweet potatoes, corn, winter squash).

5. NO GRAINS: Do NOT include any grains — no bread, pasta, rice, oats, quinoa, corn, or flour-based products. Not even "healthy whole grains."

6. NO SUGAR: Do NOT include any sugar, honey, maple syrup, agave, or sweetened products. Use stevia, erythritol, or monk fruit if sweetness is needed.

7. NO LEGUMES: Do NOT include beans, lentils, chickpeas, or peas.

8. NO MOST FRUIT: Limit fruit to small amounts of berries (raspberries, blackberries, strawberries — max ½ cup per serving). No apples, bananas, grapes, oranges, tropical fruit, or dried fruit.

9. DAIRY: Full-fat dairy is encouraged (cheese, heavy cream, butter, full-fat Greek yogurt in moderation). NEVER use low-fat or fat-free dairy.

10. ELECTROLYTES: Include salty/savory elements and mention electrolyte needs. Consider adding bone broth recommendations.

11. FAT BOMBS / KETO SNACKS: May include keto-specific snacks like fat bombs, nuts, cheese, avocado, hard-boiled eggs.

12. TRACK NET CARBS: Calculate and display net carbs (total carbs − fiber) for each meal and daily total. Ensure daily total stays under 50g.', '["olive-oil","avocado-oil","butter","ghee","coconut-oil","mct-oil","animal-fats","mayonnaise","red-meat","fatty-meat","poultry","bacon","sausage","organ-meats","deli-meat","fish-fatty","fish-lean","seafood","eggs","leafy-greens","cruciferous","zucchini-squash","asparagus","green-beans","cucumber","celery","mushrooms","peppers","tomatoes","avocado","olives","cheese","heavy-cream","sour-cream","cream-cheese","greek-yogurt-full-fat","butter","macadamia-nuts","pecans","walnuts","brazil-nuts","almonds","chia-seeds","flaxseeds","hemp-hearts","pumpkin-seeds","raspberries","blackberries","strawberries","herbs","spices","lemon-lime","vinegar","mustard","hot-sauce","soy-sauce","salt","stevia","erythritol","monk-fruit","allulose","xylitol","water","sparkling-water","coffee","tea","bone-broth","dry-wine","spirits"]', '["all-grains","bread","pasta","cereal","flour","potatoes","sweet-potatoes","yams","corn","winter-squash","cassava","tropical-fruit","tree-fruit","citrus-fruit","grapes","dried-fruit","legumes","peas","sugar","honey","maple-syrup","agave","coconut-sugar","sugary-drinks","beer","sweet-wine","cocktails","ultra-processed-food","low-fat-products","ketchup","barbecue-sauce"]', '{"extra virgin olive oil":"olive-oil","olive oil":"olive-oil","avocado oil":"avocado-oil","butter":"butter","ghee":"ghee","coconut oil":"coconut-oil","mct oil":"mct-oil","tallow":"animal-fats","lard":"animal-fats","ribeye":"fatty-meat","steak":"red-meat","beef":"red-meat","ground beef":"red-meat","pork":"red-meat","pork belly":"fatty-meat","lamb":"red-meat","bacon":"bacon","sausage":"sausage","chicken":"poultry","chicken thighs":"poultry","chicken wings":"poultry","turkey":"poultry","duck":"poultry","salmon":"fish-fatty","mackerel":"fish-fatty","sardines":"fish-fatty","herring":"fish-fatty","tuna":"fish-lean","cod":"fish-lean","shrimp":"seafood","eggs":"eggs","spinach":"leafy-greens","kale":"leafy-greens","arugula":"leafy-greens","broccoli":"cruciferous","cauliflower":"cruciferous","brussels sprouts":"cruciferous","zucchini":"zucchini-squash","asparagus":"asparagus","avocado":"avocado","mushrooms":"mushrooms","cucumber":"cucumber","potatoes":"potatoes","sweet potatoes":"sweet-potatoes","corn":"corn","cheddar cheese":"cheese","mozzarella":"cheese","cream cheese":"cream-cheese","heavy cream":"heavy-cream","sour cream":"sour-cream","greek yogurt":"greek-yogurt-full-fat","macadamia nuts":"macadamia-nuts","pecans":"pecans","walnuts":"walnuts","almonds":"almonds","chia seeds":"chia-seeds","flaxseeds":"flaxseeds","raspberries":"raspberries","blackberries":"blackberries","strawberries":"strawberries","bananas":"tropical-fruit","apples":"tree-fruit","bread":"all-grains","rice":"all-grains","pasta":"all-grains","oats":"all-grains","sugar":"sugar","honey":"honey","lentils":"legumes","chickpeas":"legumes"}',
    '["carnivore","paleo","whole30"]', '{"mediterranean":"Build a shared protein (fish/chicken/steak) + vegetable base; keto partner adds extra fat and skips grains/legumes; Mediterranean partner adds whole grains/legumes","high-protein":"Very similar — both emphasize protein; keto adds more fat, high-protein adds more carbs as needed","dash":"Shared vegetables + lean protein base; keto partner adds fats and skips grains; DASH partner adds grains and limits saturated fat","flexitarian":"Shared vegetable-forward base; keto partner adds meat/fat; flexitarian partner adds grains/legumes","volumetrics":"Shared vegetable volume; keto partner adds fat; volumetrics partner adds low-calorie carbs","vegan":"Very difficult but possible with shared low-carb vegetable base; vegan partner adds tofu/tempeh + olive oil + avocado; keto partner adds meat. Almost no shared protein.","vegetarian":"Shared eggs/cheese base; keto partner adds meat; vegetarian partner adds low-carb plant proteins"}', '{"mcdougall":"Directly opposite philosophies — McDougall is 70-80% carb, keto is 70-80% fat. Suggest separate meals.","pritikin":"Opposite fat philosophy — Pritikin is <10% fat. Suggest separate meals.","hclf-811":"Opposite philosophy — 80% carb, 10% fat raw. Suggest separate meals.","ornish":"Opposite fat philosophy — Ornish is <10% fat, very low saturated fat. Suggest separate meals."}'
  );
INSERT INTO diet_catalog (
    diet_key, display_label, category, emoji, short_desc,
    evidence_grade, restrictiveness, is_timing_pattern, is_default,
    ai_rules, allowed_groups, restricted_groups, classifier_terms,
    easy_matches, adaptable_matches, hard_conflicts
  ) VALUES (
    'high-protein', 'High-Protein', 'macronutrient-focused', '💪', 'Prioritize protein for satiety, muscle, and body composition',
    'B', 2, 0, 0,
    'HIGH-PROTEIN DIET RULES — Follow strictly:

1. PROTEIN TARGET: Every meal must contain a substantial protein portion. Aim for 25-40g of protein per main meal (breakfast, lunch, dinner). Each meal should exceed the leucine threshold (~2.5-3g leucine, equivalent to ~25-30g of animal protein or ~35-40g of plant protein).

2. PROTEIN DISTRIBUTION: Distribute protein evenly across 3-4 meals. Do NOT concentrate most of the daily protein in one meal. The pattern should be approximately: 30g breakfast / 35g lunch / 40g dinner / 15g snack(s).

3. PROTEIN SOURCE: Feature a high-quality protein source as the CENTER of each meal. Every main meal must have a clearly identifiable primary protein (e.g., chicken breast, salmon, Greek yogurt, eggs, tofu, tempeh, protein shake).

4. LEAN PROTEIN PRIORITY: Default to lean protein sources (chicken breast, turkey, white fish, egg whites, non-fat Greek yogurt, cottage cheese, tofu). Use higher-fat proteins (salmon, beef, whole eggs, cheese) in moderation.

5. BREAKFAST PROTEIN: Breakfast is critical — many people under-eat protein at breakfast. Ensure breakfast contains at least 25g of protein. Good options: Greek yogurt + eggs, protein smoothie, cottage cheese + fruit, egg white omelet with lean protein.

6. VEGETABLES REQUIRED: High-protein does NOT mean meat-only. Every meal must include vegetables (for fiber, micronutrients, and antioxidants). Aim for 2+ servings of vegetables at lunch and dinner.

7. FIBER: Total daily fiber should be 25-35g. Include legumes, vegetables, whole grains, and fruits alongside protein.

8. PROCESSED MEAT: Do NOT include processed meats (sausage, bacon, hot dogs, deli meats) as protein sources. Use fresh, whole protein sources only.

9. DAIRY: Greek yogurt and cottage cheese are excellent protein sources — include them regularly (daily is ideal).

10. PROTEIN SUPPLEMENTS: Whey or plant protein powder can be used as a convenient protein source for 1 meal/snack per day. Do NOT make supplements the sole protein source for more than 1 meal per day.

11. BALANCE: Do NOT eliminate carbohydrates or fats. Include whole grains, fruits, and healthy fats (olive oil, avocado, nuts) alongside protein. A balanced plate is: ¼ plate lean protein, ¼ plate complex carbs, ½ plate vegetables, plus a thumb of healthy fat.

12. COOKING METHOD: Favor grilling, baking, roasting, poaching, and sautéing over frying. Frying adds excessive calories and unhealthy fats.

13. RED MEAT: Lean red meat (sirloin, flank) is acceptable 2-3x/week for iron, B12, zinc, and creatine. Avoid fatty cuts (ribeye, T-bone) and processed red meat.', '["chicken-breast","turkey-breast","lean-beef","pork-tenderloin","lean-ground-meat","fish-fatty","fish-lean","seafood","whole-eggs","egg-whites","greek-yogurt","cottage-cheese","milk-skim","ricotta","string-cheese","lentils","chickpeas","black-beans","edamame","split-peas","tofu","tempeh","seitan","tvp","pumpkin-seeds","hemp-seeds","chia-seeds","peanut-butter","almonds","quinoa","whey-protein","casein-protein","plant-protein-blend","pea-protein","soy-protein","protein-bars","leafy-greens","cruciferous","peppers","asparagus","mushrooms","alliums","tomatoes","root-vegetables","berries","citrus","apples","bananas","stone-fruit","whole-grains","whole-grain-bread","olive-oil","avocado","nuts","herbs","spices","lemon-lime","garlic","water","coffee","tea"]', '["processed-meat","fried-protein","high-fat-red-meat","ultra-processed-food","sugary-drinks","refined-sugar","refined-grains","full-fat-cheese-large","high-sugar-protein-bars"]', '{"chicken breast":"chicken-breast","chicken thigh (skinless)":"chicken-breast","turkey breast":"turkey-breast","ground turkey (93/7)":"lean-ground-meat","sirloin steak":"lean-beef","flank steak":"lean-beef","tenderloin (beef)":"lean-beef","pork tenderloin":"pork-tenderloin","ground beef (93/7)":"lean-ground-meat","salmon":"fish-fatty","mackerel":"fish-fatty","sardines":"fish-fatty","tuna":"fish-lean","cod":"fish-lean","halibut":"fish-lean","tilapia":"fish-lean","shrimp":"seafood","mussels":"seafood","whole eggs":"whole-eggs","egg whites":"egg-whites","liquid egg whites":"egg-whites","greek yogurt":"greek-yogurt","cottage cheese":"cottage-cheese","ricotta":"ricotta","string cheese":"string-cheese","skim milk":"milk-skim","lentils":"lentils","chickpeas":"chickpeas","black beans":"black-beans","edamame":"edamame","tofu":"tofu","tempeh":"tempeh","seitan":"seitan","textured vegetable protein":"tvp","pumpkin seeds":"pumpkin-seeds","hemp seeds":"hemp-seeds","chia seeds":"chia-seeds","peanut butter":"peanut-butter","almonds":"almonds","quinoa":"quinoa","whey protein":"whey-protein","whey isolate":"whey-protein","casein protein":"casein-protein","pea protein":"pea-protein","plant protein blend":"plant-protein-blend","soy protein":"soy-protein","bacon":"processed-meat","sausage":"processed-meat","hot dogs":"processed-meat","deli meat":"processed-meat","pepperoni":"processed-meat","ribeye":"high-fat-red-meat","t-bone":"high-fat-red-meat","brisket":"high-fat-red-meat","pork belly":"high-fat-red-meat"}',
    '[]', '{"mediterranean":"Add more Greek yogurt, fish, poultry, and eggs to Mediterranean meals. Extremely natural combination — Mediterranean + high-protein is a popular and effective stack.","low-carb":"High-protein + low-carb is a classic and synergistic combination. Both emphasize protein and reduce processed carbs.","paleo":"Paleo is naturally high-protein. Adding explicit protein targets to paleo is seamless.","flexitarian":"Flexitarian + high-protein works by adding more eggs, dairy, tofu, and legumes. Lean meat on non-vegetarian days.","volumetrics":"Both emphasize satiety — high-protein foods are also high-satiety foods. Good overlap.","keto":"Keto is moderate-protein (1.2-1.5 g/kg). High-protein keto (up to 2.0 g/kg) is possible but may reduce ketone levels. Monitor ketosis if strict keto is the goal.","vegan":"Achievable with tofu, tempeh, seitan, legumes, and plant protein powder. Needs 10-20% more total protein than animal-based due to lower bioavailability. Include soy and pea protein.","vegetarian":"Easier than vegan — eggs and dairy provide convenient high-quality protein. Greek yogurt, cottage cheese, eggs are staples.","dash":"Compatible — DASH emphasizes lean protein and low sodium. High-protein DASH is an excellent combination for metabolic health.","mind":"Compatible — add protein-rich Mediterranean components (fish, Greek yogurt) to MIND framework.","intermittent-fasting":"Excellent combination. High-protein within the eating window preserves lean mass during fasting. Each meal in the window needs higher protein (30-50g) to compensate for fewer meals.","mcdougall":"McDougall is very low-protein (starch-based, ~10% protein). Opposite philosophy. Suggest separate meals or a compromise.","pritikin":"Pritikin is low-protein and very low-fat (~10% fat, ~15% protein). High-protein Pritikin is possible but challenging.","hclf-811":"80/10/10 raw vegan is 10% protein by design. Fundamentally incompatible with high-protein. Suggest separate meals.","carnivore":"Carnivore is ALL animal protein — technically very high-protein, but lacks fiber and plant nutrients. Suggest adding vegetables to the carnivore partners plate."}', '{"none":"High-protein is adaptable with almost all dietary patterns. The main incompatibilities are with extremely low-protein philosophies (McDougall, Pritikin, 80/10/10)."}'
  );
INSERT INTO diet_catalog (
    diet_key, display_label, category, emoji, short_desc,
    evidence_grade, restrictiveness, is_timing_pattern, is_default,
    ai_rules, allowed_groups, restricted_groups, classifier_terms,
    easy_matches, adaptable_matches, hard_conflicts
  ) VALUES (
    'plant-based', 'Plant-Based / Vegan / Vegetarian', 'plant-based', '🥗', 'Predominantly plant foods — proven for heart health, diabetes prevention, and longevity',
    'B', 3, 0, 0,
    'PLANT-BASED / VEGAN / VEGETARIAN DIET RULES — Follow strictly:

SUB-TYPE DETECTION:
- If user is "vegan": NO animal products whatsoever (no meat, fish, poultry, eggs, dairy, honey, gelatin).
- If user is "vegetarian" (lacto-ovo): NO meat, fish, or poultry. Eggs and dairy ARE allowed.
- If user is "plant-based" (flexible/WFPB): Predominantly plant foods; minimal animal products optional. Emphasize whole, unprocessed foods.

1. PROTEIN SOURCES: Center meals on legumes (lentils, beans, chickpeas), soy foods (tofu, tempeh, edamame), and whole grains. Include 2-3 servings of legumes/soy foods daily.

2. VEGETABLES: Every meal should be vegetable-forward. Aim for 5+ servings of vegetables and 3-5 servings of fruit per day. Maximize color diversity.

3. WHOLE GRAINS: Use only whole grains (brown rice, quinoa, oats, barley, whole wheat, buckwheat). Avoid white/refined grains.

4. NO ANIMAL PRODUCTS (vegan): Do NOT include any meat, poultry, fish, seafood, eggs, dairy, honey, gelatin, or other animal-derived ingredients. Check for hidden animal ingredients (whey, casein, gelatin, honey, fish sauce, anchovy paste).

5. NO MEAT/FISH/POULTRY (vegetarian): Eggs and dairy are fine. Do NOT include any meat, fish, or poultry.

6. HEALTHY FATS: Include nuts, seeds, avocado, and olive oil daily. Ground flaxseed or chia seeds (1-2 tbsp) should be included for omega-3 (ALA) content. WFPB version: minimize or eliminate extracted oils.

7. SOY: Include 1-3 servings of whole soy foods daily (tofu, tempeh, edamame, soy milk). Soy is safe and beneficial at these levels.

8. FLAVOR: Use nutritional yeast (for umami + B12 if fortified), herbs, spices, tamari/soy sauce, miso, lemon juice, and vinegars liberally. Build flavor without relying on animal-based stocks or sauces.

9. IRON: Include iron-rich plant foods (lentils, tofu, spinach, pumpkin seeds, fortified cereals) and pair with vitamin C-rich foods (citrus, bell peppers, tomatoes) to enhance absorption.

10. CALCIUM: Include calcium-rich foods daily — calcium-set tofu, fortified plant milks, leafy greens (collards, kale, bok choy), tahini. Ensure plant milk is fortified.

11. PROCESSED FOODS: Avoid ultra-processed vegan junk food (even if technically vegan). Prioritize whole, minimally processed foods. Plant-based meat alternatives are acceptable occasionally but should not be dietary staples.

12. DESSERT: Default dessert is fresh fruit. Sweets should be occasional.

13. SUPPLEMENT REMINDER: If generating meal plans or nutritional summaries for vegans, flag that B12 supplementation is MANDATORY and DHA/EPA, vitamin D, and iodine are recommended.', '["leafy-greens","cruciferous","alliums","tomatoes","peppers","root-vegetables","nightshades","cucurbit-vegetables","starchy-vegetables","mushrooms","sea-vegetables","berries","citrus","tropical-fruit","stone-fruit","pome-fruit","grapes","melons","dried-fruit","whole-grains","pasta-whole-grain","whole-grain-bread","corn","legumes","chickpeas","soy-foods","peas","nuts","seeds","nut-butters","tahini","avocado","olive-oil","coconut","dark-chocolate","plant-milk-soy","plant-milk-pea","plant-milk-oat","plant-milk-almond","plant-milk-coconut","herbs","spices","nutritional-yeast","soy-sauce","miso","lemon-lime","vinegars","garlic","ginger","maple-syrup","molasses","water","coffee","tea"]', '["red-meat","processed-meat","poultry","fish-fatty","fish-lean","seafood","eggs","dairy-milk","yogurt","cheese","butter","honey","gelatin","casein","whey","red-meat","processed-meat","poultry","fish-fatty","fish-lean","seafood","refined-grains","refined-sugar","extracted-oils","ultra-processed-food"]', '{"tofu":"soy-foods","tempeh":"soy-foods","edamame":"soy-foods","soy milk":"plant-milk-soy","natto":"soy-foods","miso":"soy-foods","seitan":"plant-protein-concentrate","nutritional yeast":"nutritional-yeast","pea protein":"plant-protein-concentrate","lentils":"legumes","chickpeas":"chickpeas","garbanzo beans":"chickpeas","black beans":"legumes","kidney beans":"legumes","pinto beans":"legumes","navy beans":"legumes","split peas":"legumes","hummus":"chickpeas","brown rice":"whole-grains","quinoa":"whole-grains","oats":"whole-grains","barley":"whole-grains","farro":"whole-grains","buckwheat":"whole-grains","whole wheat pasta":"pasta-whole-grain","white rice":"refined-grains","white bread":"refined-grains","almonds":"nuts","walnuts":"nuts","cashews":"nuts","brazil nuts":"nuts","flaxseed":"seeds","chia seeds":"seeds","hemp seeds":"seeds","pumpkin seeds":"seeds","tahini":"tahini","peanut butter":"nut-butters","avocado":"avocado","olive oil":"olive-oil","coconut oil":"coconut","beef":"red-meat","pork":"red-meat","lamb":"red-meat","chicken":"poultry","turkey":"poultry","salmon":"fish-fatty","tuna":"fish-fatty","cod":"fish-lean","shrimp":"seafood","eggs":"eggs","milk":"dairy-milk","cheese":"cheese","greek yogurt":"yogurt","butter":"butter","honey":"honey","gelatin":"gelatin","whey":"whey","casein":"casein","oat milk":"plant-milk-oat","almond milk":"plant-milk-almond","coconut milk (beverage)":"plant-milk-coconut","pea milk":"plant-milk-pea"}',
    '["flexitarian","mediterranean","mind","volumetrics"]', '{"mediterranean":"The Mediterranean diet is already plant-forward; make base meal plant-based and serve fish/poultry/cheese separately for the Mediterranean partner","pescatarian":"Base meal is plant-based; add fish for the pescatarian partners plate","flexitarian":"Nearly identical — both emphasize plant foods; flexitarian partner adds occasional meat/fish","vegetarian":"If one is vegan and the other lacto-ovo, cook vegan base meal and add eggs/cheese for the vegetarian partner","keto":"Challenging but possible — focus on tofu, tempeh, nuts, seeds, avocado, low-carb vegetables; skip grains/legumes for keto partner","paleo":"Focus on vegetables, nuts, seeds, fruit; skip grains and legumes for paleo partner (use vegetable-based substitutes)","low-fodmap":"Adapt the recipe — reduce garlic/onion (use garlic-infused oil), choose low-FODMAP vegetables, moderate legumes","dash":"Very compatible — both emphasize vegetables, fruits, legumes, whole grains"}', '{"carnivore":"Fundamental incompatibility — carnivore is all animal products, vegan is zero animal products. Suggest entirely separate meals","mcdougall":"Both are plant-based, but McDougall is very low fat (<10%) — align by using WFPB no-oil version if both agree","pritikin":"Both plant-friendly, but Pritikin is <10% fat — align by using low-fat WFPB version"}'
  );
INSERT INTO diet_catalog (
    diet_key, display_label, category, emoji, short_desc,
    evidence_grade, restrictiveness, is_timing_pattern, is_default,
    ai_rules, allowed_groups, restricted_groups, classifier_terms,
    easy_matches, adaptable_matches, hard_conflicts
  ) VALUES (
    'flexitarian', 'Flexitarian', 'plant-based', '🌱', 'Flexible vegetarian — mostly plants with occasional meat and fish',
    'B-C', 1, 0, 0,
    'FLEXITARIAN DIET RULES — Follow strictly:

SUB-TYPE DETECTION:
- Default level: "Advanced" (3-4 meatless days/week, ~3-4 meat meals/week).
- Adjust based on user''s stated preference for Beginner (2 meatless days), Advanced (3-4), or Expert (5+ meatless days).

1. PLANT-FORWARD: Every meal should be built around plants. Vegetables, fruits, whole grains, legumes, nuts, and seeds are the foundation. The majority of meals should be fully plant-based or plant-forward.

2. PROTEIN SOURCES: Prioritize plant proteins (legumes, tofu, tempeh, edamame, nuts, seeds) for MOST meals. Animal proteins (fish, poultry, eggs, dairy) are allowed but should appear in only 2-3 meals per week.

3. MEAT FREQUENCY: Limit meat/fish/poultry to 2-3 meals per week (Advanced level). When meat is included, keep portions moderate (3-5 oz / 85-140g). Prioritize fish (especially fatty fish) over poultry over red meat.

4. FISH PRIORITY: When including animal protein, PRIORITIZE fish — especially fatty fish (salmon, sardines, mackerel) for omega-3 content. This aligns with both health and flexitarian philosophy.

5. PROCESSED MEAT: Do NOT include processed meats (sausages, bacon, deli meats, hot dogs). These are minimized/avoided on the flexitarian diet.

6. RED MEAT: Include red meat only occasionally (a few times per month). Small portions (85-120g). Never feature red meat in consecutive meals.

7. VEGETABLES: Aim for 4+ servings of vegetables per day. Maximize variety and color.

8. WHOLE GRAINS: Use whole grains (brown rice, quinoa, oats, whole wheat, farro). Minimize refined grains.

9. LEGUMES: Include legumes (lentils, chickpeas, beans, tofu, tempeh) in 1-2 meals daily. These are the primary protein source on meatless days.

10. EGGS AND DAIRY: Eggs (up to 4-6/week) and moderate dairy (Greek yogurt, cheese) are allowed daily. These provide protein, B12, calcium, and iron on meatless days.

11. MEATLESS DAYS: Generate fully meatless meals for most days. Use creative plant-based mains — Buddha bowls, lentil stews, tofu stir-fries, bean-based dishes, pasta primavera, veggie curries.

12. FLAVOR: Use herbs, spices, garlic, lemon, vinegars, and nutritional yeast generously to build satisfying flavors without relying on meat.

13. DESSERT: Default dessert is fresh fruit. Sweets should be occasional.

14. NO STRICT BANS: Remember — no food is completely forbidden on the flexitarian diet. The goal is balance and predominance of plant foods, not perfection.', '["leafy-greens","cruciferous","alliums","tomatoes","peppers","root-vegetables","starchy-vegetables","nightshades","cucurbit-vegetables","mushrooms","berries","citrus","tropical-fruit","stone-fruit","pome-fruit","grapes","melons","whole-grains","pasta-whole-grain","whole-grain-bread","corn","legumes","chickpeas","soy-foods","peas","nuts","seeds","nut-butters","tahini","eggs","dairy-milk","yogurt","cheese","cottage-cheese","olive-oil","avocado","nuts","dark-chocolate","fish-fatty","fish-lean","seafood","poultry","herbs","spices","lemon-lime","vinegars","garlic","ginger","nutritional-yeast","soy-sauce","honey","maple-syrup","water","coffee","tea"]', '["processed-meat","red-meat-frequent","refined-grains","refined-sugar","sugary-drinks","fast-food","ultra-processed-food"]', '{"tofu":"soy-foods","tempeh":"soy-foods","edamame":"soy-foods","seitan":"plant-protein","nutritional yeast":"nutritional-yeast","lentils":"legumes","chickpeas":"chickpeas","black beans":"legumes","kidney beans":"legumes","hummus":"chickpeas","brown rice":"whole-grains","quinoa":"whole-grains","oats":"whole-grains","barley":"whole-grains","whole wheat pasta":"pasta-whole-grain","white rice":"refined-grains","white bread":"refined-grains","almonds":"nuts","walnuts":"nuts","flaxseed":"seeds","chia seeds":"seeds","hemp seeds":"seeds","tahini":"tahini","eggs":"eggs","greek yogurt":"yogurt","cheese":"cheese","cottage cheese":"cottage-cheese","milk":"dairy-milk","salmon":"fish-fatty","sardines":"fish-fatty","mackerel":"fish-fatty","tuna":"fish-fatty","cod":"fish-lean","shrimp":"seafood","chicken":"poultry","turkey":"poultry","beef":"red-meat","pork":"red-meat","lamb":"red-meat","bacon":"processed-meat","sausage":"processed-meat","ham":"processed-meat","deli meat":"processed-meat","hot dogs":"processed-meat","olive oil":"olive-oil","avocado":"avocado"}',
    '["mediterranean","plant-based","vegetarian","vegan","mind","dash","volumetrics","high-protein"]', '{"keto":"Make the base meal plant-forward (vegetables, eggs, cheese, nuts); add meat for keto partner. Flexitarian partner can eat the same vegetables + legumes/grains","paleo":"Both can share vegetables, nuts, fruit, eggs, fish. Flexitarian partner adds grains/legumes; paleo partner adds more meat","pescatarian":"Nearly identical — share fish and plant-based meals; flexitarian may occasionally add poultry","low-fodmap":"Adapt recipes — reduce garlic/onion, choose low-FODMAP vegetables, moderate legumes"}', '{"carnivore":"Fundamental tension — carnivore is all animal products, flexitarian is mostly plants. But its workable since flexitarian allows some meat — suggest shared protein with separate plant sides for the flexitarian partner","mcdougall":"Both are plant-forward, but McDougall is very low fat (<10%) — use oil-free cooking if needed","pritikin":"Both are plant-forward, but Pritikin is <10% fat — use oil-free cooking if needed"}'
  );
INSERT INTO diet_catalog (
    diet_key, display_label, category, emoji, short_desc,
    evidence_grade, restrictiveness, is_timing_pattern, is_default,
    ai_rules, allowed_groups, restricted_groups, classifier_terms,
    easy_matches, adaptable_matches, hard_conflicts
  ) VALUES (
    'paleo', 'Paleo', 'ancestral', '🦴', 'Eat like a hunter-gatherer — meat, fish, vegetables, nuts; no grains, dairy, or legumes',
    'C', 4, 0, 0,
    'PALEO DIET RULES — Follow strictly:

1. NO GRAINS: Do NOT include any grains — no wheat, rice, oats, corn, barley, rye, quinoa, or products made from them (bread, pasta, cereal, tortillas, flour-based items). This is absolute.

2. NO LEGUMES: Do NOT include beans, lentils, chickpeas, peanuts, soy, tofu, or tempeh. Use coconut aminos instead of soy sauce.

3. NO DAIRY: Do NOT include milk, cheese, yogurt, butter, or cream. (Ghee may be used in modified versions.) Use coconut milk or almond milk as substitutes.

4. NO REFINED SUGAR: Do NOT use white sugar, brown sugar, or artificial sweeteners. Honey, maple syrup, and coconut sugar are acceptable in moderation.

5. NO REFINED OILS: Do NOT use canola, soybean, sunflower, safflower, corn, or cottonseed oil. Use olive oil, avocado oil, coconut oil, tallow, or ghee (modified).

6. PROTEIN AT EVERY MEAL: Include a high-quality protein source (meat, fish, eggs) at every meal. Prioritize grass-fed, pasture-raised, and wild-caught.

7. VEGETABLES AS THE BASE: Every meal should feature vegetables prominently. Aim for 5+ servings of non-starchy vegetables per day.

8. FISH: Include fish or seafood at least 3 times per week. Prioritize fatty fish (salmon, sardines, mackerel) for omega-3 content.

9. HEALTHY FATS: Use olive oil, avocado oil, coconut oil, or animal fats for cooking. Include avocado, nuts, and seeds for additional fats.

10. STARCHY CARBS: Carbohydrates come from sweet potatoes, plantains, squash, and fruits — NOT grains. Include starchy vegetables especially for active individuals.

11. NO PROCESSED FOODS: All foods should be whole and minimally processed. Avoid anything with artificial ingredients, preservatives, emulsifiers, or unrecognizable ingredients.

12. FLAVOR: Season with herbs, spices, garlic, citrus, and vinegar. Natural salt in moderation (strict versions exclude added salt).', '["red-meat","poultry","pork","organ-meats","fish-fatty","fish-lean","seafood","eggs","leafy-greens","cruciferous","alliums","peppers","nightshades","root-vegetables","cucurbit-vegetables","winter-squash","mushrooms","asparagus-green-beans","berries","citrus","stone-fruit","tropical-fruit","pome-fruit","melons","grapes","avocado","sweet-potato","plantains","cassava-taro","nuts","seeds","coconut","olive-oil","avocado-oil","coconut-oil","animal-fats","ghee","herbs","spices","lemon-lime","vinegar","honey","maple-syrup","coconut-sugar","water","sparkling-water","coffee","tea","bone-broth"]', '["all-grains","grain-products","pseudo-cereals","legumes","peanuts","soy","peas","dairy","butter","refined-sugar","refined-grains","seed-oils","margarine","processed-food","processed-meat","fast-food","white-potatoes","added-salt","soda","juice"]', '{"salmon":"fish-fatty","sardines":"fish-fatty","mackerel":"fish-fatty","trout":"fish-fatty","tuna":"fish-fatty","cod":"fish-lean","halibut":"fish-lean","sea bass":"fish-lean","shrimp":"seafood","mussels":"seafood","oysters":"seafood","scallops":"seafood","grass-fed beef":"red-meat","beef":"red-meat","bison":"red-meat","lamb":"red-meat","venison":"red-meat","pork":"pork","bacon":"processed-meat","sausage":"processed-meat","chicken":"poultry","turkey":"poultry","duck":"poultry","liver":"organ-meats","eggs":"eggs","spinach":"leafy-greens","kale":"leafy-greens","broccoli":"cruciferous","cauliflower":"cruciferous","brussels sprouts":"cruciferous","sweet potato":"sweet-potato","plantain":"plantains","avocado":"avocado","zucchini":"cucurbit-vegetables","tomato":"nightshades","eggplant":"nightshades","blueberries":"berries","strawberries":"berries","banana":"tropical-fruit","apple":"pome-fruit","almonds":"nuts","walnuts":"nuts","macadamia nuts":"nuts","pecans":"nuts","pumpkin seeds":"seeds","flaxseed":"seeds","chia seeds":"seeds","coconut":"coconut","extra virgin olive oil":"olive-oil","olive oil":"olive-oil","avocado oil":"avocado-oil","coconut oil":"coconut-oil","tallow":"animal-fats","ghee":"ghee","rice":"all-grains","wheat":"all-grains","oats":"all-grains","quinoa":"pseudo-cereals","bread":"grain-products","pasta":"grain-products","lentils":"legumes","chickpeas":"legumes","black beans":"legumes","peanuts":"peanuts","peanut butter":"peanuts","tofu":"soy","tempeh":"soy","milk":"dairy","cheese":"dairy","yogurt":"dairy","butter":"butter","canola oil":"seed-oils","soybean oil":"seed-oils","white potato":"white-potatoes"}',
    '["whole30","keto","high-protein","low-carb"]', '{"mediterranean":"Share the fish, vegetables, olive oil, and nuts components; add whole grains and dairy for the Mediterranean partner","flexitarian":"Share the vegetable-forward base; Paleo partner adds more meat, flexitarian adds grains/legumes","volumetrics":"Both emphasize vegetables and whole foods; add grains for volumetrics partner","vegan":"Very challenging but possible — build around vegetables, fruits, nuts, seeds, avocado; vegan adds legumes/grains, paleo adds meat/fish","vegetarian":"Similar to vegan; paleo partner adds meat/fish, vegetarian adds dairy/legumes/grains"}', '{"mcdougall":"Opposite philosophy — McDougall is starch-centric (potatoes, rice, grains) and very low fat; Paleo eliminates most McDouall staples","pritikin":"Opposite fat philosophy (Pritikin is <10% fat, plant-based); Paleo is 35-45% fat","hclf-811":"Opposite macronutrient profile — raw, high-carb, low-fat; Paleo is moderate-carb, high-protein, high-fat","vegetarian-indian":"Traditional Indian vegetarian cuisine relies heavily on grains (rice, wheat), legumes (dal, chickpeas), and dairy (paneer, ghee) — all excluded on Paleo"}'
  );
INSERT INTO diet_catalog (
    diet_key, display_label, category, emoji, short_desc,
    evidence_grade, restrictiveness, is_timing_pattern, is_default,
    ai_rules, allowed_groups, restricted_groups, classifier_terms,
    easy_matches, adaptable_matches, hard_conflicts
  ) VALUES (
    'whole30', 'Whole30', 'ancestral', '🚫', '30-day elimination reset — identify food sensitivities and break sugar cravings',
    'C-D', 5, 0, 0,
    'WHOLE30 ELIMINATION PHASE RULES — Follow with ZERO exceptions:

1. NO SUGAR OF ANY KIND: Do NOT include any added sugar — no cane sugar, brown sugar, honey, maple syrup, agave, coconut sugar, stevia, monk fruit, or any artificial sweetener. This is absolute. Read all labels mentally.

2. NO ALCOHOL: Do NOT include any alcohol — no wine, beer, spirits, or alcohol-based extracts (vanilla extract is OUT).

3. NO GRAINS: Do NOT include any grains — no wheat, rice, oats, corn, barley, rye, quinoa, buckwheat, or any flour (including almond flour and coconut flour for baking).

4. NO LEGUMES: Do NOT include beans, lentils, chickpeas, peanuts, soy, tofu, tempeh, or soy sauce (use coconut aminos). Green beans, snow peas, and snap peas ARE allowed.

5. NO DAIRY: Do NOT include milk, cheese, yogurt, butter, cream, or whey. GHEE (clarified butter) is the ONLY exception.

6. NO CARRAGEENAN, MSG, OR SULFITES: Check all ingredients for these additives.

7. NO RECREATING: Do NOT create "compliant versions" of off-plan foods — no pancakes, muffins, cookies, banana ice cream, cauliflower rice (as rice substitute), or zucchini noodles (as pasta substitute). Use compliant ingredients naturally, not to mimic prohibited foods.

8. PROTEIN AT EVERY MEAL: Include a protein source (meat, fish, or eggs) at every meal.

9. VEGETABLES AT EVERY MEAL: Fill your plate with vegetables. Aim for variety and abundance.

10. WHOLE FOODS ONLY: All foods should be whole, unprocessed, and have compliant ingredients. If you can''t pronounce an ingredient or don''t know what it is, don''t use it.

11. POTATOES ARE ALLOWED: Both white and sweet potatoes are compliant on Whole30.

12. FRUIT IS ALLOWED: Fresh fruit is fine. Dried fruit is fine in moderation. Fruit juice is ONLY allowed as a recipe ingredient (e.g., lemon juice in dressing), NOT as a beverage or sweetener.

13. NO WEIGHING OR MEASURING: Focus on how food makes you feel, not on numbers.', '[]', '[]', '{"salmon":"fish-fatty","sardines":"fish-fatty","mackerel":"fish-fatty","tuna":"fish-fatty","cod":"fish-lean","halibut":"fish-lean","shrimp":"seafood","scallops":"seafood","crab":"seafood","beef":"red-meat","bison":"red-meat","lamb":"red-meat","pork":"red-meat","chicken":"poultry","turkey":"poultry","duck":"poultry","eggs":"eggs","bacon":"compliant-processed-meat","sausage":"compliant-processed-meat","spinach":"leafy-greens","kale":"leafy-greens","broccoli":"cruciferous","cauliflower":"cruciferous","white potato":"white-potatoes","potato":"white-potatoes","sweet potato":"sweet-potato","tomato":"nightshades","eggplant":"nightshades","bell pepper":"peppers","zucchini":"cucurbit-vegetables","green beans":"green-beans","snap peas":"snap-peas","avocado":"avocado","mushrooms":"mushrooms","blueberries":"berries","strawberries":"berries","banana":"tropical-fruit","apple":"pome-fruit","lemon":"citrus","lime":"citrus","almonds":"nuts","walnuts":"nuts","macadamia nuts":"nuts","cashews":"nuts","pumpkin seeds":"seeds","flaxseed":"seeds","coconut":"coconut","almond butter":"nut-butters","extra virgin olive oil":"olive-oil","olive oil":"olive-oil","avocado oil":"avocado-oil","coconut oil":"coconut-oil","ghee":"ghee","tallow":"animal-fats","coconut aminos":"coconut-aminos","apple cider vinegar":"vinegar","balsamic vinegar":"vinegar","mustard":"mustard","hot sauce":"hot-sauce","salt":"salt","black pepper":"spices","garlic powder":"spices","onion powder":"spices","honey":"natural-sweeteners","maple syrup":"natural-sweeteners","stevia":"artificial-sweeteners","monk fruit":"artificial-sweeteners","sugar":"added-sugar","vanilla extract":"alcohol-extracts","wine":"alcohol","beer":"alcohol","rice":"all-grains","oats":"all-grains","quinoa":"pseudo-cereals","corn":"all-grains","bread":"grain-products","pasta":"grain-products","almond flour":"grain-flours","coconut flour":"grain-flours","lentils":"legumes","chickpeas":"legumes","peanut butter":"peanuts","tofu":"soy","soy sauce":"soy","milk":"dairy","cheese":"dairy","yogurt":"dairy","butter":"dairy","cream":"dairy","carrageenan":"carrageenan","msg":"msg"}',
    '["paleo"]', '{"keto":"Very compatible — both eliminate grains, sugar, dairy. Keto allows dairy and focuses on macros; Whole30 allows more carbs from fruit/potatoes","high-protein":"Similar emphasis on protein at every meal","low-carb":"Compatible during elimination phase","mediterranean":"Share the fish, vegetables, olive oil, nuts base; Mediterranean partner adds whole grains, dairy, legumes","flexitarian":"Share the vegetable base; Whole30 partner adds more meat","volumetrics":"Both emphasize vegetables; Whole30 is more restrictive on fats and protein sources"}', '{"vegan":"Nearly impossible — Whole30 eliminates all vegan protein sources (legumes, soy, dairy). Cannot be done as a vegan","vegetarian":"Very difficult — eliminates legumes, soy, and dairy. Only protein sources are eggs and nuts","mcdougall":"Opposite philosophy — McDougall is starch/grain-centric and very low fat; Whole30 eliminates all grains","hclf-811":"Opposite — raw, high-carb, high-fruit, low-fat; Whole30 is moderate-carb, high-protein, high-fat with strict food restrictions","vegetarian-indian":"Traditional Indian vegetarian cuisine relies on grains, legumes, and dairy — all eliminated on Whole30"}'
  );
INSERT INTO diet_catalog (
    diet_key, display_label, category, emoji, short_desc,
    evidence_grade, restrictiveness, is_timing_pattern, is_default,
    ai_rules, allowed_groups, restricted_groups, classifier_terms,
    easy_matches, adaptable_matches, hard_conflicts
  ) VALUES (
    'low-fodmap', 'Low FODMAP', 'therapeutic', '🫃', 'Elimination diet for IBS — removes fermentable carbs that trigger bloating',
    'B', 4, 0, 0,
    'LOW FODMAP DIET RULES — Follow strictly (ELIMINATION PHASE):

1. NO ONION OR GARLIC: Do NOT include onion (any type), garlic (fresh, powder, salt, or paste) in any recipe. Use garlic-infused olive oil for garlic flavor. Use spring onion GREENS ONLY or chives for onion flavor. Asafoetida (hing) can substitute for both.

2. GRAINS: Use rice, quinoa, oats (moderate portions), potatoes, corn, or gluten-free grains. Avoid wheat-based bread/pasta in main dishes. (Small amounts of wheat in soy sauce are fine.)

3. DAIRY: Use lactose-free milk and yogurt, or hard cheeses (cheddar, Swiss, parmesan, brie, feta). Avoid regular cow''s milk, regular yogurt, ice cream, ricotta, and regular cottage cheese. Butter is fine.

4. FRUITS: Use bananas (firm-ripe), blueberries, strawberries, oranges, kiwi, mandarins, raspberries, pineapple. Avoid apples, pears, watermelon, mangoes, honey, agave, dried fruits.

5. VEGETABLES: Use spinach, zucchini, bell peppers, carrots, tomatoes (moderate), cucumber, green beans, lettuce, eggplant, kale, bok choy. Avoid onions, garlic, mushrooms, cauliflower, large amounts of celery, asparagus, Brussels sprouts.

6. LEGUMES: Avoid lentils, chickpeas, and beans during elimination. Use firm tofu and tempeh as plant protein.

7. NUTS: Limit almonds to 10, walnuts to 10 halves. Avoid cashews and pistachios entirely.

8. PROTEINS: All plain meat, fish, poultry, eggs, and firm tofu are safe. Watch out for marinades/seasonings containing onion or garlic powder.

9. SWEETENERS: Use maple syrup or rice malt syrup. Do NOT use honey or agave. Avoid sugar alcohols (xylitol, sorbitol, maltitol).

10. LABEL CHECKING: Be aware that onion powder, garlic powder, inulin, chicory root, honey, agave, and high-fructose corn syrup are common additives in sauces, dressings, and processed foods.

11. FLAVOR STRATEGY: Rely on herbs (basil, oregano, thyme, rosemary, parsley, cilantro), spices (cumin, paprika, turmeric, ginger, cinnamon), lemon/lime juice, garlic-infused oil, spring onion greens, and chives for flavor.

12. PORTION AWARENESS: Many foods are low FODMAP only at specific serving sizes. When in doubt, use conservative portions. Cross-reference with Monash app thresholds.

PHASE NOTE: If user is in REINTRODUCTION or PERSONALIZATION phase, relax restrictions for the specific FODMAP subgroup(s) they have tested and tolerate.', '["rice","oats","quinoa","potatoes","corn","gluten-free-grains","rice-noodles","sourdough-spelt","chicken","turkey","beef","pork","lamb","fish-all","seafood","eggs","tofu-firm","tempeh","spinach","zucchini","bell-peppers","carrots","tomatoes","cucumber","green-beans","lettuce","eggplant","kale","bok-choy","pumpkin","bean-sprouts","potatoes","bananas","blueberries","strawberries","oranges","kiwi","mandarins","raspberries","pineapple","cantaloupe","papaya","lemon-lime","lactose-free-milk","lactose-free-yogurt","hard-cheese","feta","butter","lactose-free-cottage-cheese","almonds","walnuts","pecans","macadamia-nuts","peanuts","pine-nuts","pumpkin-seeds","sesame-seeds","chia-seeds","sunflower-seeds","olive-oil","coconut-oil","peanut-butter","garlic-infused-oil","herb-infused-oils","herbs-all","spices-all","spring-onion-green","chives","asafoetida","soy-sauce","maple-syrup","rice-malt-syrup","vinegar-all","mustard-plain","miso-paste","water","coffee","tea-black","tea-green","tea-peppermint","tea-chamomile"]', '["wheat-large-amounts","rye","barley","onion-all","garlic-all","leeks-bulb","asparagus","artichoke-globe","inulin-chicory-root","brussels-sprouts","savoy-cabbage","lentils-large","chickpeas-large","beans-large","soy-milk-whole-bean","pistachios","cashews","cow-milk","regular-yogurt","ice-cream","ricotta","cottage-cheese-regular","soft-cheese-lactose","apples","pears","watermelon","mangoes","honey","agave-nectar","high-fructose-corn-syrup","dried-fruit","cherries-large","apple-juice","pear-juice","avocado-large","mushrooms","cauliflower-large","celery-large","blackberries","stone-fruit-large","apricots","sugar-alcohols"]', '{"salmon":"fish-all","cod":"fish-all","tuna":"fish-all","chicken":"chicken","turkey":"turkey","beef":"beef","shrimp":"seafood","eggs":"eggs","firm tofu":"tofu-firm","tempeh":"tempeh","cheddar":"hard-cheese","parmesan":"hard-cheese","feta":"feta","lactose-free milk":"lactose-free-milk","rice":"rice","quinoa":"quinoa","oats":"oats","potatoes":"potatoes","rice noodles":"rice-noodles","wheat bread":"wheat-large-amounts","regular pasta":"wheat-large-amounts","spinach":"spinach","zucchini":"zucchini","bell pepper":"bell-peppers","carrots":"carrots","tomatoes":"tomatoes","cucumber":"cucumber","onion":"onion-all","garlic":"garlic-all","mushrooms":"mushrooms","cauliflower":"cauliflower-large","banana":"bananas","blueberries":"blueberries","strawberries":"strawberries","orange":"oranges","kiwi":"kiwi","apple":"apples","pear":"pears","watermelon":"watermelon","almonds":"almonds","walnuts":"walnuts","cashews":"cashews","pistachios":"pistachios","olive oil":"olive-oil","garlic-infused oil":"garlic-infused-oil","butter":"butter","honey":"honey","maple syrup":"maple-syrup"}',
    '["gluten-free","dairy-free"]', '{"mediterranean":"Adapt recipes — use garlic-infused oil instead of garlic, spring onion greens instead of onion, rice/quinoa instead of wheat, limit legumes","paleo":"Good overlap — both emphasize whole foods, meat, fish, vegetables; adapt vegetables (avoid onion, garlic, mushrooms, cauliflower)","whole30":"Similar whole-food approach; swap non-compliant items","high-protein":"Easy — most protein sources are low FODMAP; just avoid onion/garlic seasonings","keto":"Possible — focus on meat, fish, eggs, low-FODMAP vegetables, olive oil; avoid high-FODMAP keto foods (avocado large portions, cauliflower, garlic)"}', '{"vegan":"Difficult — most plant protein sources (legumes) are high FODMAP; requires careful tofu/tempeh planning and B12 monitoring","mcdougall":"Opposite philosophy — McDougall emphasizes wheat, potatoes, and starches; wheat is high FODMAP; very difficult to combine","raw-vegan":"Difficult — many raw fruits/vegetables are high FODMAP; limited options","mediterranean":"Manageable but requires significant modification — onion, garlic, wheat, and legumes are Mediterranean staples"}'
  );
INSERT INTO diet_catalog (
    diet_key, display_label, category, emoji, short_desc,
    evidence_grade, restrictiveness, is_timing_pattern, is_default,
    ai_rules, allowed_groups, restricted_groups, classifier_terms,
    easy_matches, adaptable_matches, hard_conflicts
  ) VALUES (
    'mind', 'MIND', 'balanced', '🧠', 'Mediterranean-DASH hybrid optimized for brain health and cognition',
    'B', 2, 0, 0,
    'MIND DIET RULES — Follow strictly:

1. LEAFY GREENS: Include at least 1 serving of green leafy vegetables in at least one meal every day (spinach, kale, collard greens, arugula, Swiss chard, romaine). This is the #1 MIND priority.

2. BERRIES: Include berries (blueberries, strawberries, blackberries, raspberries) at least 2-3 times per week. Blueberries and strawberries have the strongest cognitive evidence. Frozen berries are acceptable.

3. OLIVE OIL: Use extra virgin olive oil as the PRIMARY (ideally ONLY) cooking fat. Do NOT use butter, margarine, or vegetable oils as the main cooking fat. Olive oil should be used for dressings, sautéing, roasting, and finishing.

4. FISH: Include fish at least 1-2 times per week. Prioritize fatty fish rich in DHA/EPA (salmon, sardines, mackerel, trout). This provides essential omega-3 for brain structure.

5. NUTS: Include a handful of nuts (especially walnuts and almonds) at least 5 times per week — ideally daily. Walnuts provide omega-3 ALA; almonds provide vitamin E.

6. WHOLE GRAINS: Use only whole grains (100% whole wheat bread, brown rice, oats, quinoa, barley, farro). Aim for 3+ servings/day. Avoid refined grains.

7. BEANS/LEGUMES: Include legumes (lentils, chickpeas, beans) in at least 3 meals per week. They provide stable blood sugar and B vitamins for brain energy.

8. POULTRY: Include skinless chicken or turkey at least 2 times per week as a lean protein source.

9. VEGETABLES: Include at least 1 serving of non-leafy vegetables per day in addition to leafy greens (broccoli, tomatoes, carrots, peppers, Brussels sprouts, etc.).

10. RED MEAT: Limit to <4 meals per week. Optimal: 1-2 small portions per week. Never feature red meat in consecutive meals.

11. CHEESE: Limit to <1 serving per week. This is stricter than the Mediterranean diet — do NOT include cheese daily.

12. BUTTER/MARGARINE: Avoid as cooking fat. Replace with olive oil entirely.

13. FRIED/FAST FOOD: Do NOT include fried foods or fast food in meal plans.

14. PASTRIES/SWEETS: Do NOT feature pastries, cookies, or sugary desserts. Default dessert is berries or fresh fruit.

15. WINE: May include 1 glass of red wine with dinner (optional — do not add to breakfast or lunch. Non-drinkers should not be encouraged to start).

16. BRAIN FOOD PRIORITY ORDER: Leafy greens > Berries > Olive oil > Fish > Nuts > Whole grains > Beans > Poultry', '["leafy-greens","tomatoes","alliums","cruciferous","peppers","root-vegetables","other-vegetables","cucurbit-vegetables","nuts","nut-butters","seeds","berries","berries-frozen","legumes","soy-beans","whole-grains","whole-grain-pasta","whole-grain-cereal","popcorn","fish-fatty","fish-lean","poultry-skinless","poultry","olive-oil","wine","eggs","low-fat-dairy","coffee","tea","herbs","spices","lemon-lime","vinegar","garlic","water","sparkling-water"]', '["red-meat","butter","stick-margarine","cheese","pastries","refined-sugar","ice-cream","sugary-drinks","fried-food","fast-food","ultra-processed-food","processed-meat","refined-grains","trans-fat"]', '{"spinach":"leafy-greens","kale":"leafy-greens","collard greens":"leafy-greens","swiss chard":"leafy-greens","arugula":"leafy-greens","romaine lettuce":"leafy-greens","mixed greens":"leafy-greens","watercress":"leafy-greens","mustard greens":"leafy-greens","beet greens":"leafy-greens","bok choy":"leafy-greens","blueberries":"berries","strawberries":"berries","blackberries":"berries","raspberries":"berries","cranberries":"berries","goji berries":"berries","acai":"berries","frozen blueberries":"berries-frozen","frozen strawberries":"berries-frozen","extra virgin olive oil":"olive-oil","olive oil":"olive-oil","salmon":"fish-fatty","sardines":"fish-fatty","mackerel":"fish-fatty","herring":"fish-fatty","anchovies":"fish-fatty","trout":"fish-fatty","tuna":"fish-fatty","cod":"fish-lean","halibut":"fish-lean","walnuts":"nuts","almonds":"nuts","pistachios":"nuts","pecans":"nuts","hazelnuts":"nuts","mixed nuts":"nuts","peanut butter":"nut-butters","flaxseeds":"seeds","chia seeds":"seeds","lentils":"legumes","chickpeas":"legumes","black beans":"legumes","kidney beans":"legumes","navy beans":"legumes","split peas":"legumes","edamame":"soy-beans","tofu":"soy-beans","brown rice":"whole-grains","wild rice":"whole-grains","oats":"whole-grains","steel-cut oats":"whole-grains","quinoa":"whole-grains","barley":"whole-grains","farro":"whole-grains","bulgur":"whole-grains","100% whole wheat bread":"whole-grains","whole wheat pasta":"whole-grain-pasta","chicken breast":"poultry-skinless","turkey breast":"poultry-skinless","ground turkey":"poultry","beef":"red-meat","steak":"red-meat","pork":"red-meat","lamb":"red-meat","bacon":"processed-meat","sausage":"processed-meat","ham":"processed-meat","deli meat":"processed-meat","butter":"butter","margarine":"stick-margarine","cheddar cheese":"cheese","mozzarella":"cheese","parmesan":"cheese","feta":"cheese","cream cheese":"cheese","cookies":"pastries","cake":"pastries","donuts":"pastries","pastries":"pastries","ice cream":"ice-cream","french fries":"fried-food","fried chicken":"fried-food","banana":"non-berry-fruit","apple":"non-berry-fruit","orange":"non-berry-fruit","grapes":"non-berry-fruit","eggs":"eggs","milk":"low-fat-dairy","greek yogurt":"low-fat-dairy","coffee":"coffee","green tea":"tea","lemon juice":"lemon-lime","balsamic vinegar":"vinegar","garlic":"garlic"}',
    '["mediterranean","dash","flexitarian","volumetrics","high-protein"]', '{"vegan":"Replace fish/poultry with beans, nuts, and algae-based omega-3 (DHA) supplement. Replace wine with grape juice or skip. Base MIND is very plant-forward already.","vegetarian":"Same base meal; add fish/poultry only for non-vegetarian partner. Easy adaptation.","pescatarian":"Nearly identical — MIND already emphasizes fish. Remove poultry, add more fish.","keto":"Focus on leafy greens + fish + nuts + olive oil components. Replace whole grains and beans with extra non-starchy vegetables. Berries are keto-compatible in moderation.","paleo":"Focus on fish + leafy greens + nuts + berries + olive oil. Skip whole grains and legumes for paleo partner. Can include red meat (MIND allows <4/week).","low-fodmap":"Adapt — reduce garlic/onion (use garlic-infused olive oil), choose low-FODMAP vegetables, moderate legumes, choose low-FODMAP nuts (walnuts OK in small amounts)."}', '{"carnivore":"Very difficult — MIND is plant-forward with daily vegetables and weekly legumes. Suggest separate meals with shared fish/poultry protein.","mcdougall":"Partial overlap (both emphasize whole grains and beans) but MIND includes nuts, olive oil, fish, and wine which McDougall restricts.","pritikin":"Partial overlap (both plant-forward, low saturated fat) but Pritikin is very low fat (<10%) while MIND emphasizes olive oil and nuts."}'
  );
INSERT INTO diet_catalog (
    diet_key, display_label, category, emoji, short_desc,
    evidence_grade, restrictiveness, is_timing_pattern, is_default,
    ai_rules, allowed_groups, restricted_groups, classifier_terms,
    easy_matches, adaptable_matches, hard_conflicts
  ) VALUES (
    'pritikin', 'Pritikin', 'therapeutic', '💚', 'Very low-fat (<10%), high complex carb — designed to reverse heart disease',
    'B-C', 5, 0, 0,
    'PRITIKIN DIET RULES — Follow strictly:

1. NO ADDED FAT: Do NOT use ANY oil, butter, margarine, lard, or any added fat in cooking or as a garnish. This includes olive oil, coconut oil, and all "healthy" oils. This is the single most important rule.

2. COOKING METHOD: Sauté vegetables using the "water sauté" technique — use small amounts of water, vegetable broth, or wine instead of oil. Steam, boil, bake, or roast vegetables. Use parchment paper or silicone mats for baking (no oil spray).

3. VEGETABLES: Feature vegetables prominently and abundantly in every meal. Aim for 7+ servings/day. All vegetables are allowed in unlimited quantities.

4. WHOLE GRAINS: Use only whole, unrefined grains — brown rice, oats, quinoa, barley, bulgur, whole wheat. NEVER use white rice, white flour, or regular (white) pasta.

5. LEGUMES: Include legumes (beans, lentils, chickpeas) daily. They are a primary protein source.

6. FRUITS: All whole fruits are allowed freely. Use fruits as natural sweeteners.

7. NO HIGH-FAT PLANT FOODS: Do NOT include nuts, seeds, avocado, coconut, or olives. Ground flaxseed (1 tbsp/day) is the ONLY seed exception.

8. ANIMAL PROTEIN: Very limited. Use lean white fish (cod, flounder, halibut) — max 3.5 oz/serving, up to 4x/week. Skinless chicken/turkey breast — max 3.5 oz, up to 2-3x/week. NO red meat, NO processed meat, NO dark poultry.

9. NO EGGS (whole): Egg whites only, occasionally. No whole eggs or egg yolks.

10. NO DAIRY: No milk, cheese, cream, yogurt, ice cream, or butter of any fat content.

11. NO REFINED SUGAR: No table sugar, honey, maple syrup, agave, corn syrup, candy, or desserts. Sweeten with whole fruits only.

12. FLAVOR WITHOUT FAT: Use herbs, spices, garlic, onion, lemon juice, lime juice, vinegar (all types), mustard (no oil), salsa, and nutritional yeast for flavor. These are critical for making fat-free food palatable.

13. SODIUM: Minimize added salt. Aim for <1,500mg sodium/day. Use herbs and spices instead of salt.

14. DESSERT: Default dessert is fresh fruit. No sweetened baked goods.

15. BEVERAGES: Water, black coffee, unsweetened tea. Limit 100% fruit juice to 4 oz/day. Minimize or avoid alcohol.

16. EXERCISE: Note in meal plans that the Pritikin Program includes 30+ minutes of daily aerobic exercise.', '["leafy-greens","cruciferous","alliums","peppers","root-vegetables","nightshades","cucurbit-vegetables","winter-squash","tomatoes","asparagus","green-beans","mushrooms","artichokes","celery","fennel","berries","citrus","stone-fruit","tropical","melons","pome-fruit","grapes","dried-fruit-unsweetened","whole-grains","whole-wheat","corn-whole","whole-grain-cereal","legumes","soy-lean","potatoes","winter-squash-starchy","herbs","spices","garlic","onion","lemon-lime","vinegar-all","mustard-no-fat","salsa","tomato-sauce-no-fat","nutritional-yeast","water","coffee","tea","sparkling-water","fruit-juice-100"]', '["all-oils","butter","ghee","margarine","lard-tallow","shortening","mayonnaise","salad-dressing-oil","pesto","nut-butters","nuts","seeds","avocado","coconut","olives","dark-chocolate","red-meat","processed-meat","dark-poultry","organ-meats","duck-goose","whole-eggs","full-fat-dairy","butter-dairy","low-fat-dairy","refined-grains","refined-sugar","sugary-drinks","syrups","fast-food","frozen-meals","snack-foods","baked-goods","ultra-processed-food"]', '{"cod":"lean-fish","flounder":"lean-fish","halibut":"lean-fish","sole":"lean-fish","salmon":"fatty-fish-restricted","mackerel":"fatty-fish-restricted","shrimp":"shellfish","scallops":"shellfish","chicken breast":"lean-poultry","turkey breast":"lean-poultry","beef":"red-meat","pork":"red-meat","lamb":"red-meat","bacon":"processed-meat","sausage":"processed-meat","eggs":"whole-eggs","egg whites":"allowed","tofu":"soy-lean","tempeh":"soy-lean","lentils":"legumes","chickpeas":"legumes","black beans":"legumes","milk":"full-fat-dairy","cheese":"full-fat-dairy","greek yogurt":"full-fat-dairy","brown rice":"whole-grains","quinoa":"whole-grains","oats":"whole-grains","barley":"whole-grains","whole wheat bread":"whole-wheat","whole wheat pasta":"whole-wheat","white rice":"refined-grains","white bread":"refined-grains","regular pasta":"refined-grains","olive oil":"all-oils","extra virgin olive oil":"all-oils","coconut oil":"all-oils","butter":"butter","margarine":"margarine","almonds":"nuts","walnuts":"nuts","avocado":"avocado","coconut":"coconut","olives":"olives","peanut butter":"nut-butters","spinach":"leafy-greens","kale":"leafy-greens","broccoli":"cruciferous","onion":"alliums","garlic":"alliums","bell pepper":"peppers","carrots":"root-vegetables","tomatoes":"tomatoes","potatoes":"potatoes","bananas":"tropical","blueberries":"berries","oranges":"citrus","apples":"pome-fruit","honey":"syrups","maple syrup":"syrups","sugar":"refined-sugar"}',
    '["ornish","esselstyn","mcdougall","vegan"]', '{"vegetarian":"Pritikin already allows limited animal protein; simply add a dairy/egg option for the vegetarian partners plate if they consume it","dash":"Some overlap — both are high in vegetables/fruits and low in sodium. DASH allows moderate fat; modify to accommodate both","flexitarian":"Flexitarian is more flexible; Pritikin partner removes oils/fats, flexitarian partner adds moderate fat/protein to their plate","whole30":"Difficult — Whole30 requires fat and allows meat; Pritikin eliminates both. Very difficult to find common ground"}', '{"keto":"Directly OPPOSITE philosophy — keto is 60-75% fat; Pritikin is <10% fat. Completely incompatible. Suggest completely separate meals.","carnivore":"Directly opposite — carnivore is all animal foods; Pritikin is nearly all plant foods. Completely incompatible.","mediterranean":"Opposite fat philosophy — Mediterranean is 30-40% fat with liberal olive oil; Pritikin is <10% fat. Very difficult; suggest separate meals.","paleo":"Difficult — paleo emphasizes meat, fat, and excludes grains/legumes; Pritikin is opposite. Suggest separate meals.","atkins":"Opposite macronutrient philosophy. Completely incompatible."}'
  );
INSERT INTO diet_catalog (
    diet_key, display_label, category, emoji, short_desc,
    evidence_grade, restrictiveness, is_timing_pattern, is_default,
    ai_rules, allowed_groups, restricted_groups, classifier_terms,
    easy_matches, adaptable_matches, hard_conflicts
  ) VALUES (
    'carnivore', 'Carnivore', 'lowCarb', '🥩', 'Animal foods only — zero carb, zero plants. Extreme elimination approach.',
    'D', 5, 0, 0,
    'CARNIVORE DIET RULES — Follow strictly:

1. ANIMAL FOODS ONLY: Every meal must consist EXCLUSIVELY of animal products — meat, fish, eggs, and optionally dairy. NO plant foods of any kind.

2. NO VEGETABLES: Do NOT include any vegetables — no leafy greens, no broccoli, no cauliflower, no tomatoes, no peppers, no onions, no garlic, no mushrooms, no avocado, no zucchini, NO plant matter of any kind.

3. NO FRUIT: Do NOT include any fruit — no berries, no apples, no lemons (even as garnish), no avocado.

4. NO GRAINS: Do NOT include any grains — no bread, no rice, no pasta, no oats.

5. NO LEGUMES: Do NOT include beans, lentils, chickpeas, or peas.

6. NO NUTS OR SEEDS: Do NOT include any nuts, seeds, or seed-derived products.

7. NO PLANT OILS: Use ONLY animal fats for cooking — tallow, lard, duck fat, butter, or ghee. Do NOT use olive oil, coconut oil, avocado oil, or any plant oil.

8. MEAT IS THE FOCUS: Each meal should center on a substantial portion of meat (225-450g / 8-16oz). Ribeye steak, ground beef, brisket, pork belly, lamb chops, or fatty fish are typical mains.

9. FAT IS ESSENTIAL: Ensure adequate fat intake. Choose fatty cuts (ribeye, 80/20 ground beef, pork belly) or add tallow/butter. Lean meat alone is dangerous ("rabbit starvation").

10. SALT: Use salt liberally. It is the primary and often only seasoning.

11. EGGS AND DAIRY: Eggs are included freely. Dairy (cheese, butter, heavy cream) is optional — include if the user has not excluded it. When in doubt, include butter but ask about other dairy.

12. ORGAN MEATS: Recommend including organ meats (especially liver) 1-2 times per week for nutrient density, if the user is willing.

13. BEVERAGES: Water and bone broth only (unless the user specifies they include coffee/tea). Do NOT include juice, herbal tea, or any plant-based beverage.

14. ZERO CARB CALCULATION: Daily carbohydrate total should be effectively zero (trace amounts from meat/eggs/dairy only, typically <5g).

15. DO NOT add herbs, spices, lemon juice, vinegar, or any plant-derived seasoning unless the user explicitly states they are a "lenient" carnivore.', '["red-meat","fatty-meat","poultry","pork","bacon","sausage","organ-meats","deli-meat","fish-fatty","fish-lean","seafood","eggs","beef-tallow","lard","duck-fat","butter","ghee","bone-marrow","animal-fats","cheese","cream-cheese","heavy-cream","sour-cream","butter-dairy","bone-broth","salt","water","sparkling-water","bone-broth-beverage"]', '["all-vegetables","leafy-greens","cruciferous","tomatoes","peppers","root-vegetables","onions-garlic","mushrooms","avocado","zucchini-squash","all-fruits","berries","citrus","tropical-fruit","dried-fruit","all-grains","bread","pasta","cereal","all-legumes","all-nuts","all-seeds","olive-oil","coconut-oil","avocado-oil","seed-oils","all-plant-oils","sugar","honey","maple-syrup","stevia","monk-fruit","erythritol","fruit-juice","vegetable-juice","herbal-tea","wine","beer","ultra-processed-food","soy-products","plant-based-meat","plant-extracts"]', '{"ribeye":"fatty-meat","steak":"red-meat","beef":"red-meat","ground beef":"red-meat","brisket":"fatty-meat","short ribs":"fatty-meat","pork":"pork","pork belly":"fatty-meat","pork chops":"pork","bacon":"bacon","lamb":"red-meat","venison":"red-meat","bison":"red-meat","chicken":"poultry","chicken thighs":"poultry","chicken wings":"poultry","turkey":"poultry","duck":"poultry","liver":"organ-meats","beef liver":"organ-meats","heart":"organ-meats","kidney":"organ-meats","bone marrow":"bone-marrow","sweetbreads":"organ-meats","salmon":"fish-fatty","mackerel":"fish-fatty","sardines":"fish-fatty","herring":"fish-fatty","tuna":"fish-lean","cod":"fish-lean","shrimp":"seafood","oysters":"seafood","eggs":"eggs","egg yolks":"eggs","beef tallow":"beef-tallow","tallow":"beef-tallow","lard":"lard","duck fat":"duck-fat","butter":"butter","ghee":"ghee","cheddar cheese":"cheese","parmesan":"cheese","heavy cream":"heavy-cream","bone broth":"bone-broth","salt":"salt","spinach":"all-vegetables","broccoli":"all-vegetables","tomatoes":"all-vegetables","avocado":"all-fruits","olive oil":"all-plant-oils","coconut oil":"all-plant-oils","almonds":"all-nuts","rice":"all-grains","bread":"all-grains","bananas":"all-fruits","lemon":"all-fruits","lentils":"all-legumes","sugar":"sugar","stevia":"stevia"}',
    '["keto","paleo"]', '{"high-protein":"Shared meat/protein focus; carnivore partner eats meat only; high-protein partner adds vegetables/grains","whole30":"Both eliminate processed foods; shared meat base; Whole30 partner adds vegetables, fruit, compliant carbs","mediterranean":"Carnivore is plant-free; Mediterranean is plant-forward. Can share a protein (steak, fish, chicken) but carnivore partner eats only the meat; Mediterranean partner adds vegetables, grains, olive oil, salad. Suggest cooking a shared protein and separate side dishes.","flexitarian":"Carnivore partner eats only animal foods; flexitarian partner eats mostly plants with some meat. Minimal shared base.","volumetrics":"Opposite approaches — volumetrics relies on high-volume plant foods; carnivore is all animal. Suggest separate meals.","dash":"DASH is plant-forward and low-saturated-fat; carnivore is the opposite. Very difficult."}', '{"vegan":"MAXIMUM conflict — vegan excludes ALL animal products; carnivore excludes ALL plant products. Zero overlap. Suggest completely separate meals.","vegetarian":"Nearly maximum conflict — only eggs/dairy overlap (if carnivore includes them). Very difficult.","mcdougall":"Maximum conflict — McDougall is 70-80% carbohydrate from starches; carnivore is zero carb. Opposites.","pritikin":"Maximum conflict — Pritikin is <10% fat, plant-forward; carnivore is 70%+ fat, animal-only.","ornish":"Maximum conflict — Ornish is <10% fat, plant-based; carnivore is high-fat, animal-only.","hclf-811":"Maximum conflict — 80% carb, 10% fat, raw plant foods; carnivore is the exact opposite.","mind":"Strong conflict — MIND is plant-forward for brain health; carnivore is plant-free.","anti-inflammatory":"Most anti-inflammatory diets are plant-forward; carnivore contradicts this approach."}'
  );
INSERT INTO diet_catalog (
    diet_key, display_label, category, emoji, short_desc,
    evidence_grade, restrictiveness, is_timing_pattern, is_default,
    ai_rules, allowed_groups, restricted_groups, classifier_terms,
    easy_matches, adaptable_matches, hard_conflicts
  ) VALUES (
    'mcdougall', 'McDougall (Starch Solution)', 'plant-based', '🥔', 'Starch-centered, very low-fat, strictly plant-based — unlimited potatoes, rice & beans',
    'C-D', 4, 0, 0,
    'McDOUGALL / STARCH SOLUTION DIET RULES — Follow strictly:

1. STARCH IS THE CENTER: Every meal MUST feature a generous portion of starch (potatoes, sweet potatoes, rice, beans, lentils, corn, oats, quinoa, pasta, squash). Starch should be 50-80% of the plate by volume. Do NOT make vegetables the largest portion — starches should dominate.

2. NO ANIMAL PRODUCTS: Do NOT include ANY meat, poultry, fish, seafood, eggs, or dairy. This is a strictly vegan diet.

3. NO ADDED FAT: Do NOT use ANY oil (olive, canola, coconut, sesame, or any other). Do NOT use butter, margarine, or any extracted fat. Sauté vegetables with water, broth, or wine instead of oil.

4. NO HIGH-FAT PLANT FOODS: Avoid nuts, seeds, avocado, olives, and coconut in meal generation. The ONLY exception is 1 tbsp ground flaxseed per day (for omega-3).

5. UNLIMITED PORTIONS: Meals should be generous. Do NOT restrict portion sizes of approved starches and vegetables. The diet relies on eating until satisfied.

6. VEGETABLES: Include vegetables with every meal, but they are secondary to starches. Use oil-free cooking methods (steaming, boiling, baking, water-sautéing).

7. FRUIT: Include 1-3 servings of fresh fruit per day (as snack or dessert). Limit dried fruit.

8. FLAVOR WITHOUT FAT: Season with herbs, spices, garlic, lemon juice, vinegars, nutritional yeast, low-sodium soy sauce, mustard, and salsa. NEVER use oil or butter for flavor.

9. WHOLE GRAINS ONLY: Use whole grains (brown rice, whole wheat, oats, quinoa, barley). White rice is acceptable but whole grains preferred. Avoid refined flour products in Maximum Weight Loss mode.

10. BEANS AND LEGUMES: Include beans, lentils, or peas daily. They are a key starch AND protein source.

11. NO DAIRY SUBSTITUTES WITH OIL: Avoid vegan cheeses, commercial vegan dressings, or plant-based creams that contain added oils.

12. SATISFYING PORTIONS: Generate meals that are visually large and filling. The McDougall diet is NOT about restriction — it is about abundance of the right foods.', '["potatoes","sweet-potatoes","rice","beans","lentils","peas","corn","oats","barley","wheat-berries","quinoa","buckwheat","millet","teff","sorghum","winter-squash","whole-grain-pasta","whole-grain-bread","leafy-greens","cruciferous","root-vegetables","alliums","summer-squash","nightshades","green-beans","mushrooms","cucurbit-vegetables","fresh-fruit","dried-fruit","herbs","spices","lemon-lime","vinegars","garlic","nutritional-yeast","soy-sauce-tamari","mustard","hot-sauce","salsa","miso","tofu","edamame","soy-milk"]', '["red-meat","poultry","fish-all","eggs","dairy-all","processed-meat","all-oils","butter","margarine","shortening-lard","refined-grains","refined-sugar","sugary-drinks","fast-food","ultra-processed-food","artificial-sweeteners","vegan-junk-food","alcohol","coffee","fruit-juice"]', '{"potatoes":"potatoes","russet potatoes":"potatoes","sweet potatoes":"sweet-potatoes","yams":"sweet-potatoes","rice":"rice","brown rice":"rice","white rice":"rice","basmati rice":"rice","black beans":"beans","pinto beans":"beans","kidney beans":"beans","navy beans":"beans","cannellini beans":"beans","garbanzo beans":"beans","chickpeas":"beans","adzuki beans":"beans","lentils":"lentils","green lentils":"lentils","red lentils":"lentils","split peas":"peas","green peas":"peas","corn":"corn","oats":"oats","steel-cut oats":"oats","barley":"barley","quinoa":"quinoa","buckwheat":"buckwheat","millet":"millet","whole wheat pasta":"whole-grain-pasta","butternut squash":"winter-squash","acorn squash":"winter-squash","spinach":"leafy-greens","kale":"leafy-greens","broccoli":"cruciferous","cauliflower":"cruciferous","carrots":"root-vegetables","onions":"alliums","garlic":"alliums","tomatoes":"nightshades","bell peppers":"nightshades","zucchini":"summer-squash","mushrooms":"mushrooms","nutritional yeast":"nutritional-yeast","soy sauce":"soy-sauce-tamari","tamari":"soy-sauce-tamari","miso":"miso","salsa":"salsa","olive oil":"all-oils","coconut oil":"all-oils","vegetable oil":"all-oils","sesame oil":"all-oils","butter":"butter","margarine":"margarine","beef":"red-meat","chicken":"poultry","salmon":"fish-all","tuna":"fish-all","eggs":"eggs","milk":"dairy-all","cheese":"dairy-all","yogurt":"dairy-all","flaxseed":"flaxseed","walnuts":"nuts","almonds":"nuts","avocado":"avocado","tofu":"tofu"}',
    '["ornish","esselstyn","wfpb","vegan","pritikin"]', '{"vegetarian":"Same base meal (starch + vegetables + beans); the vegetarian partner can add eggs or dairy to their portion","flexitarian":"Same base meal; flexitarian partner adds a small portion of fish or lean meat","mediterranean":"DIFFICULT — opposite fat philosophy. Share the starch + vegetable base; Mediterranean partner adds olive oil, fish, and feta to their plate. Must use separate cooking for oil-based components","dash":"Share the starch + vegetable + bean base; DASH partner adds lean protein and moderate healthy fats. Sodium target is similar","volumetrics":"Very compatible — both emphasize low calorie density and large portions"}', '{"keto":"OPPOSITE MACRONUTRIENT PHILOSOPHY — McDougall is 75% carb / 10% fat; keto is 10% carb / 75% fat. Essentially no shared meal possible. Suggest entirely separate meals","carnivore":"OPPOSITE IN EVERY WAY — carnivore is all animal products, zero plants. No shared foods whatsoever. Must cook completely separate meals","paleo":"Major conflict — Paleo excludes grains, beans, and legumes (the core of McDougall). Suggest separate starch/protein components","atkins":"Opposite carbohydrate philosophy. No shared meal structure possible","hclf-811":"Not a conflict per se, but 80/10/10 is raw-food focused while McDougall includes cooked starches. Compatible in philosophy but different in execution"}'
  );
INSERT INTO diet_catalog (
    diet_key, display_label, category, emoji, short_desc,
    evidence_grade, restrictiveness, is_timing_pattern, is_default,
    ai_rules, allowed_groups, restricted_groups, classifier_terms,
    easy_matches, adaptable_matches, hard_conflicts
  ) VALUES (
    'macrobiotic', 'Macrobiotic', 'plant-based', '🍚', 'Whole grain-centered, yin-yang balanced — brown rice, miso, seasonal vegetables & sea vegetables',
    'C-D', 4, 0, 0,
    'MACROBIOTIC DIET RULES — Follow strictly:

1. WHOLE GRAINS ARE THE FOUNDATION: Every meal MUST feature a substantial portion of whole grain (40-60% of the meal by volume). Brown rice (especially short-grain) should be the primary grain. Other grains (barley, millet, oats, buckwheat, quinoa) can be rotated for variety. Do NOT use refined grains (white rice, white flour).

2. MISO SOUP DAILY: Include miso soup (miso paste + wakame seaweed + vegetables) at least once per day, ideally at breakfast. Add miso at the end of cooking (do NOT boil miso — it destroys beneficial enzymes).

3. VEGETABLES: Include vegetables with every meal (20-30% by volume). Prioritize seasonal, local vegetables: leafy greens (kale, bok choy), root vegetables (carrots, daikon, burdock), cruciferous (cabbage, broccoli), and winter squash.

4. BEANS AND SOY FOODS: Include beans or soy foods daily (5-10% by volume). Adzuki beans are the most macrobiotically favored. Tofu, tempeh, and natto are excellent protein sources.

5. SEA VEGETABLES: Include small amounts of sea vegetables daily (nori, wakame, kombu, arame, dulse). Do NOT use hijiki (arsenic risk). Add kombu to beans during cooking to improve digestibility.

6. CONDIMENTS: Include traditional macrobiotic condiments — gomashio (sesame salt), umeboshi plum, tekka — in small amounts. Include pickled/fermented vegetables daily.

7. COOKING METHODS: Use pressure cooking for grains and beans, steaming for vegetables, and slow-simmering (nishime) for root vegetables. Use gas flame preferred over electric. Do NOT use microwave ovens.

8. SEASONAL AWARENESS: Adjust food choices by season — lighter cooking and more cooling vegetables in summer; heartier, warmer dishes and root vegetables in winter.

9. NIGHTSHADE RESTRICTION (strict version): In the strict macrobiotic version, AVOID potatoes, tomatoes, eggplant, and bell peppers. NOTE: This restriction has no scientific basis and may be relaxed in modern versions.

10. NO REFINED SUGAR: Do NOT use refined sugar. If sweetening is needed, use rice syrup, barley malt, or amasake (natural grain sweeteners).

11. BEVERAGES: Primary beverage is bancha/kukicha tea (roasted twig tea) or water. Do NOT include coffee or alcohol.

12. ANIMAL PRODUCTS: In the strict version, include NO animal products. In relaxed/modified versions, small amounts of fresh white fish (halibut, cod, flounder) may be included 2-3 times per week. Do NOT include red meat, poultry, eggs, or dairy.

13. FLAVOR BALANCE: Season with tamari (natural soy sauce), miso, umeboshi, rice vinegar, and ginger. Avoid hot spices (cayenne, chili) and excessive salt.

14. CHEWING & MINDFULNESS: Include a reminder about thorough chewing (50+ times per bite) and mindful eating in meal descriptions.', '["brown-rice","barley","millet","oats","buckwheat","quinoa","wheat-berries","corn-whole","rye","sweet-rice","leafy-greens","root-vegetables","alliums","cruciferous","winter-squash","green-vegetables","mushrooms","sea-vegetables","adzuki-beans","chickpeas","lentils","black-beans","tofu","tempeh","natto","miso-soup","vegetable-soup","grain-soup","gomashio","umeboshi","tekka","tamari","pickled-vegetables","brown-rice-vinegar","miso-paste","temperate-fruits","nuts-roasted","natural-sweeteners","white-fish","bancha-tea","water","grain-coffee","herbal-teas"]', '["refined-sugar","refined-grains","processed-foods","fast-food","ultra-processed-food","coffee","alcohol","sugary-drinks","red-meat","poultry","eggs","dairy-all","potatoes","tomatoes","eggplant","peppers","tropical-fruit","citrus","hot-spices","nightshades-all","tropical-foods"]', '{"brown rice":"brown-rice","short grain brown rice":"brown-rice","medium grain brown rice":"brown-rice","long grain brown rice":"brown-rice","barley":"barley","millet":"millet","steel-cut oats":"oats","buckwheat":"buckwheat","soba noodles":"buckwheat","quinoa":"quinoa","wheat berries":"wheat-berries","bulgur":"wheat-berries","farro":"wheat-berries","cornmeal":"corn-whole","polenta":"corn-whole","rye berries":"rye","sweet rice":"sweet-rice","mochi":"sweet-rice","kale":"leafy-greens","bok choy":"leafy-greens","napa cabbage":"leafy-greens","watercress":"leafy-greens","daikon":"root-vegetables","burdock root":"root-vegetables","carrots":"root-vegetables","turnips":"root-vegetables","parsnips":"root-vegetables","onions":"alliums","leeks":"alliums","scallions":"alliums","cabbage":"cruciferous","broccoli":"cruciferous","cauliflower":"cruciferous","pumpkin":"winter-squash","butternut squash":"winter-squash","shiitake mushrooms":"mushrooms","maitake mushrooms":"mushrooms","nori":"sea-vegetables","wakame":"sea-vegetables","kombu":"sea-vegetables","kelp":"sea-vegetables","arame":"sea-vegetables","dulse":"sea-vegetables","hijiki":"sea-vegetables","adzuki beans":"adzuki-beans","chickpeas":"chickpeas","lentils":"lentils","black beans":"black-beans","tofu":"tofu","tempeh":"tempeh","natto":"natto","miso":"miso-paste","miso soup":"miso-soup","gomashio":"gomashio","umeboshi":"umeboshi","tekka":"tekka","tamari":"tamari","shoyu":"tamari","brown rice vinegar":"brown-rice-vinegar","apple":"temperate-fruits","pear":"temperate-fruits","berries":"temperate-fruits","sesame seeds":"nuts-roasted","pumpkin seeds":"nuts-roasted","rice syrup":"natural-sweeteners","barley malt":"natural-sweeteners","amasake":"natural-sweeteners","halibut":"white-fish","cod":"white-fish","flounder":"white-fish","bancha tea":"bancha-tea","kukicha tea":"bancha-tea","grain coffee":"grain-coffee","white rice":"refined-grains","white flour":"refined-grains","white sugar":"refined-sugar","coffee":"coffee","wine":"alcohol","beer":"alcohol","beef":"red-meat","chicken":"poultry","eggs":"eggs","milk":"dairy-all","cheese":"dairy-all","potatoes":"potatoes","tomatoes":"tomatoes","eggplant":"nightshades-all","bell peppers":"nightshades-all","banana":"tropical-fruit","mango":"tropical-fruit"}',
    '["vegan","vegetarian","wfpb","mediterranean"]', '{"mcdougall":"Both grain-centered and plant-based. Share the brown rice + vegetable + bean base. McDougall partner skips miso (sodium) and sea vegetables; macrobiotic partner can add miso and sea vegetables","flexitarian":"Share the whole grain + vegetable base; flexitarian partner adds fish, eggs, or lean meat to their portion","pescatarian":"Very compatible — both include fish (in relaxed macrobiotic). Share whole grain, vegetable, and fish meals","dash":"Share the whole grain + vegetable + bean base; DASH partner adds lean protein and healthy fats. NOTE: macrobiotic can be high-sodium from miso — may need sodium adjustment for DASH partner","ornish":"Similar in being low-fat and plant-based. Share the grain + vegetable base. Ornish is more explicitly low-fat; macrobiotic partner can add small amounts of sesame oil","mind":"Both emphasize whole grains and vegetables. MIND partner adds berries and nuts (which macrobiotic limits)"}', '{"keto":"OPPOSITE — macrobiotic is high-carb/grain-based; keto is very low-carb. No shared meal structure possible. Must cook completely separate meals","carnivore":"OPPOSITE IN EVERY WAY — carnivore is all animal products, zero plants. No shared foods whatsoever","paleo":"Major conflict — Paleo excludes all grains, beans, and legumes (the core of macrobiotic). Suggest separate meals","atkins":"Opposite carbohydrate philosophy. No shared meal structure","hclf-811":"Not a conflict in philosophy, but 80/10/10 is raw-food focused while macrobiotic emphasizes cooked foods. Different in execution"}'
  );
INSERT INTO diet_catalog (
    diet_key, display_label, category, emoji, short_desc,
    evidence_grade, restrictiveness, is_timing_pattern, is_default,
    ai_rules, allowed_groups, restricted_groups, classifier_terms,
    easy_matches, adaptable_matches, hard_conflicts
  ) VALUES (
    'volumetrics', 'Volumetrics', 'balanced', '⚖️', 'Eat more food, fewer calories — fill up on low energy density foods',
    'B-C', 1, 0, 0,
    'VOLUMETRICS DIET RULES — Follow strictly:

1. ENERGY DENSITY AWARENESS: Classify all foods by energy density (cal/g). Bias the meal toward Category 1 (0-0.6 cal/g) and Category 2 (0.6-1.5 cal/g) foods. Use Category 3 (1.5-4 cal/g) foods in small portions. Minimize Category 4 (4-9 cal/g) foods.

2. SOUP STARTER: Begin lunch and dinner with a bowl of broth-based soup (vegetable, chicken, miso, minestrone). Do NOT use cream-based soups. This is the signature Volumetrics strategy.

3. VEGETABLE VOLUME: Every meal should feature a large volume of non-starchy vegetables. Aim for 5+ servings/day. Fill at least 50% of the plate with vegetables.

4. FRUIT AS DEFAULT: Fruit is the default dessert and snack. Berries, melon, apples, and citrus are preferred.

5. LEAN PROTEIN: Use lean protein sources (skinless chicken breast, turkey, white fish, legumes, egg whites, tofu, low-fat dairy). Limit fatty meats.

6. WHOLE GRAINS: Use whole grains (oatmeal, brown rice, quinoa, whole wheat pasta). Avoid refined grains.

7. HEALTHY FATS — PORTION CONTROLLED: Olive oil, nuts, seeds, and avocado are allowed but must be used in SMALL, MEASURED portions due to high energy density. Use 1 tbsp oil for dressing, 1 oz nuts as a snack. Do not pour freely.

8. NO CALORIC BEVERAGES: Avoid soda, juice, and sweetened coffee drinks. Water, unsweetened tea, and black coffee are the primary beverages.

9. SATIETY FOCUS: Meals should be designed to maximize volume and fullness. Add vegetables to everything (double the veg in any recipe). Incorporate water-rich foods.

10. NO FRIED FOODS: Avoid fried foods entirely. Use grilling, baking, roasting, steaming, or sautéing (minimal oil).

11. SALAD STARTER (alternative to soup): If soup is not used, begin the meal with a large, low-calorie salad (greens + vegetables + light vinaigrette — NO creamy dressings, minimal cheese).

12. WATER IN FOOD: Incorporate water into the food itself (soups, stews, water-rich fruits/vegetables). Do NOT simply recommend drinking a glass of water with the meal.', '["non-starchy-vegetables","leafy-greens","cruciferous","watery-vegetables","alliums","peppers","mushrooms","broth-based-soups","berries","melons","citrus","stone-fruit","pome-fruit","grapes","whole-grains","pasta-whole-grain","legumes","lean-protein","fish-lean","egg-whites","tofu","low-fat-dairy","starchy-vegetables","winter-squash","whole-grain-bread","cheese","eggs","lean-red-meat","dark-meat-poultry","nuts","seeds","olive-oil","avocado","nut-butters","dark-chocolate","dried-fruit","herbs","spices","lemon-lime","vinegar","garlic","water","coffee","tea","broth"]', '["fried-foods","fast-food","ultra-processed-snacks","cream-based-soups","caloric-beverages","full-fat-dairy","processed-meat","refined-grains","refined-sugar","sugary-drinks","butter","margarine"]', '{}',
    '["mediterranean","dash","mind","flexitarian","high-protein","vegan","vegetarian","pescatarian"]', '{"keto":"Volumetrics emphasizes carbs (produce, grains) which conflicts with keto; however, the focus on non-starchy vegetables and lean protein is compatible — keto partner skips grains/fruit and adds healthy fats","paleo":"Compatible on vegetables and lean protein; paleo partner skips grains and legumes; Volumetrics produce emphasis is aligned","low-fodmap":"Adapt — reduce high-FODMAP vegetables (onion, garlic, certain fruits); choose low-FODMAP produce within the energy density framework"}', '{"hclf-811":"Different philosophies but can share a produce-heavy base meal; HCLF partner adds much more fruit and skips protein/animal foods","carnivore":"Volumetrics is produce-centric; carnivore partner needs separate meals","mcdougall":"Compatible on plant-food emphasis; McDougall allows cooked starches which fit Category 2; Volumetrics adds more produce and allows lean protein","pritikin":"Very compatible — both are low-fat, high-produce; Pritikin is slightly more restrictive"}'
  );
INSERT INTO diet_catalog (
    diet_key, display_label, category, emoji, short_desc,
    evidence_grade, restrictiveness, is_timing_pattern, is_default,
    ai_rules, allowed_groups, restricted_groups, classifier_terms,
    easy_matches, adaptable_matches, hard_conflicts
  ) VALUES (
    'hclf-811', '80/10/10 (HCLF Raw Vegan)', 'plant-based', '🍌', 'Raw vegan, fruit-based — 80% carbs, 10% protein, 10% fat',
    'D', 5, 0, 0,
    '80/10/10 (HCLF RAW VEGAN) DIET RULES — Follow strictly:

1. RAW ONLY: All foods must be raw (uncooked). Do NOT include any food heated above 118°F (48°C). No cooked grains, cooked vegetables, cooked legumes, baked goods, hot soups, coffee, or hot tea.

2. VEGAN ONLY: No animal products of ANY kind — no meat, poultry, fish, seafood, eggs, dairy, honey, or gelatin.

3. FRUIT IS THE CALORIE BASE: Sweet fruit provides 70-90% of total calories. Meals should feature large quantities of a single fruit (mono-meals) or simple fruit combinations. Bananas, dates, mangoes, grapes, melons are primary calorie sources.

4. MACRO TARGET: ≥80% carbs, ~10% protein, ≤10% fat. Do NOT include oils, butter, or any extracted fat. Keep overt fats (avocado, nuts, seeds) to very small amounts, used sparingly.

5. LEAFY GREENS: Include tender leafy greens daily, typically in a large evening salad (1+ head of lettuce or large bowl of mixed greens).

6. MONO-MEALS PREFERRED: Breakfast and lunch should ideally be mono-meals (a single fruit eaten in large quantity). Example: 15-20 bananas, or 1 large watermelon, or 8-10 mangoes.

7. NO OILS: Absolutely no oils of any kind (no olive oil, coconut oil, etc.). Dressings should be made from blended fruit (e.g., mango + tomato + celery).

8. NO SALT: Do not add salt. Rely on the natural sodium in celery and other vegetables.

9. NO PROCESSED FOODS: No packaged snacks, vegan meat substitutes, vegan cheese, refined sugar, white flour, or processed foods of any kind.

10. DINNER STRUCTURE: Dinner is typically a large green salad (romaine, spinach, tomatoes, cucumber, bell peppers, celery) with a fruit-based dressing, followed by additional fruit.

11. OVERT FATS (sparingly): If including overt fats, limit to ½ avocado OR 1 oz nuts/seeds, 1-3 times per WEEK maximum. Do not combine overt fats with sweet fruit in the same meal.

12. BEVERAGES: Water and fresh fruit juice only. No coffee, hot tea, alcohol, or bottled/pasteurized juice.

13. SUPPLEMENTATION NOTE: Always include a reminder that vitamin B12 supplementation is MANDATORY on this diet. Vitamin D and algae-based DHA/EPA are strongly recommended.

14. CALORIE ADEQUACY: Ensure the meal plan provides sufficient calories (2,500-3,500+ for most adults). Under-eating is a common and dangerous mistake on this diet due to the bulk of fruit required.

HEALTH WARNING: This diet has no clinical trial evidence (Grade D). It carries significant risk of B12 deficiency, amenorrhea, low bone mass, and dental erosion. All users should be advised to supplement B12, monitor bloodwork, and consult a healthcare provider.', '["bananas","dates","mangoes","grapes","melons","papaya","pineapple","stone-fruit","pome-fruit","citrus","berries","tropical-fruit","figs","persimmons","leafy-greens","celery","tomatoes","cucumbers","peppers","zucchini","raw-vegetables","avocado","raw-nuts","raw-seeds","young-coconut","fresh-herbs","lemon-lime","raw-tomato","water","fresh-fruit-juice","spring-water"]', '["red-meat","poultry","fish-fatty","fish-lean","seafood","eggs","dairy","honey","gelatin","cooked-grains","cooked-vegetables","cooked-legumes","baked-goods","cooked-soups","all-oils","butter","margarine","vegan-cheese","vegan-meat","refined-sugar","refined-grains","packaged-snacks","ultra-processed-food","salt","vinegar","soy-sauce","coffee","tea-hot","alcohol","oils","dried-coconut","nutritional-yeast"]', '{}',
    '["raw-vegan","fruitarian"]', '{"vegan":"Very difficult — standard vegan includes cooked foods, grains, tofu, processed alternatives that are all prohibited on 80/10/10. Can share a salad base; vegan partner adds cooked grains/legumes/tofu","vegetarian":"Same as vegan plus even more divergence with dairy/eggs. Suggest separate meals","mcdougall":"Share the high-carb, low-fat philosophy; diverge on raw vs. cooked. Both partners can eat from a shared produce base but McDougall partner needs cooked starches","pritikin":"Share the low-fat principle; diverge on raw vs. cooked and on animal protein. Suggest shared produce with separate protein/starch components"}', '{"mediterranean":"Hard conflict — Mediterranean includes olive oil, fish, cheese, bread, wine — ALL prohibited on 80/10/10. Suggest entirely separate meals; shared base limited to a salad (without dressing)","keto":"Maximum conflict — opposite macronutrient philosophy (80% fat vs. 80% carb). Completely incompatible meal structures","paleo":"Hard conflict — paleo includes meat, cooked foods, oils. Only overlap is raw vegetables and fruit","carnivore":"Maximum conflict — zero overlap. No shared foods possible","high-protein":"Hard conflict — 80/10/10 deliberately limits protein to 10%; high-protein diets target 30%+","volumetrics":"Different philosophies; can share a produce-heavy base but volumetrics allows cooked foods, lean protein, and measured oils. Suggest shared salad/fruit with separate protein and starch","flexitarian":"Very difficult — flexitarian includes cooked foods, meat occasionally, dairy, eggs. Minimal overlap beyond produce","dash":"Hard conflict — DASH includes low-fat dairy, lean protein, whole grains (cooked). Suggest separate meals","low-fodmap":"Near-impossible — 80/10/10 requires enormous quantities of high-FODMAP fruit (bananas, mangoes, dates, watermelon, apples). Cannot be adapted without violating core principles"}'
  );
