INSERT INTO diet_catalog (
    diet_key, display_label, category, emoji, short_desc,
    evidence_grade, restrictiveness, is_timing_pattern, is_default,
    ai_rules, allowed_groups, restricted_groups, classifier_terms,
    easy_matches, adaptable_matches, hard_conflicts
  ) VALUES (
    'vegan', 'Vegan', 'plantBased', '', 'No animal products — plant-based only',
    'A', 3, 0, 0,
    'VEGAN DIET RULES:
1. No meat, poultry, fish, seafood, eggs, dairy, or honey.
2. All protein must come from plant sources (legumes, tofu, tempeh, seitan, nuts, seeds).
3. Include fortified foods or supplements for B12, vitamin D, and omega-3 (algae-based).
4. Emphasize variety of vegetables, fruits, whole grains, legumes, nuts, and seeds.', '["legumes","vegetables","fruits","whole-grains","nuts","seeds","tofu","tempeh"]', '["red-meat","poultry","fish","seafood","eggs","dairy","honey","processed-meat"]', '{"chicken":"poultry","beef":"red-meat","pork":"red-meat","lamb":"red-meat","salmon":"fish","tuna":"fish","shrimp":"seafood","eggs":"eggs","cheese":"dairy","milk":"dairy","butter":"dairy","yogurt":"dairy","cream":"dairy","whey":"dairy","honey":"honey"}',
    '["vegetarian","plant-based","flexitarian"]', '{"mediterranean":"Make base plant-based, add fish separately for non-vegan partner"}', '{"carnivore":"Fundamental conflict — no shared foods","keto":"Very difficult — almost no shared protein sources"}'
  );
INSERT INTO diet_catalog (
