    easy_matches, adaptable_matches, hard_conflicts
  ) VALUES (
    'pescatarian', 'Pescatarian', 'plantBased', '', 'No meat — fish and seafood OK',
    'A', 2, 0, 0,
    'PESCATARIAN DIET RULES:
1. No red meat or poultry.
2. Fish and seafood are allowed and encouraged.
3. Eggs and dairy are allowed.
4. Include fatty fish (salmon, sardines, mackerel) 1-2x per week for omega-3.', '["fish","seafood","eggs","dairy","vegetables","fruits","whole-grains","legumes","nuts","seeds"]', '["red-meat","poultry","processed-meat"]', '{"chicken":"poultry","beef":"red-meat","pork":"red-meat","lamb":"red-meat","turkey":"poultry","bacon":"processed-meat"}',
    '["vegetarian","mediterranean","plant-based","flexitarian"]', '{"keto":"Use fish + low-carb vegetables as shared base"}', '{"carnivore":"Fundamental conflict"}'
  );

